/* NSW Selective Test Prep — Year 6 Mathematical Reasoning question bank.
   140 verified questions: 4 weekly mock exams x 35 questions.
   5 categories x 7 questions per week.
   Shared by app.html (interactive) and workbook.html (printable). */
const CATEGORIES = [
  "Number and Algebra",
  "Measurement and Geometry",
  "Statistics and Probability",
  "Problem Solving",
  "Data Interpretation"
];
const QUESTIONS = [
  {"id":"NA-W1-Q1","week":1,"category":"Number and Algebra","topic":"ratios","difficulty":"M","estSecs":70,"question":"A baker mixes flour and sugar in the ratio 5 : 3. In one batch she uses 2 kg more flour than sugar. How much flour does she use in that batch?","options":{"A":"1 kg","B":"5 kg","C":"3 kg","D":"8 kg","E":"2.5 kg"},"answer":"B","explanation":"Flour is 5 parts and sugar is 3 parts, so the difference is 5 - 3 = 2 parts. This difference equals 2 kg, so 2 parts = 2 kg, meaning 1 part = 1 kg. Flour is 5 parts = 5 x 1 kg = 5 kg. (Sugar would be 3 kg and the total 8 kg.)"},
  {"id":"NA-W1-Q2","week":1,"category":"Number and Algebra","topic":"fractions of quantities","difficulty":"M","estSecs":70,"question":"A water tank is 3/4 full. After 24 litres are drawn off, the tank is exactly 1/2 full. What is the total capacity of the tank?","options":{"A":"48 L","B":"120 L","C":"32 L","D":"72 L","E":"96 L"},"answer":"E","explanation":"The amount removed corresponds to the drop from 3/4 full to 1/2 full: 3/4 - 1/2 = 1/4 of the tank. So 1/4 of the capacity = 24 L, which means the full capacity = 4 x 24 = 96 L. Check: 3/4 of 96 = 72 L and 1/2 of 96 = 48 L, and 72 - 48 = 24 L."},
  {"id":"NA-W1-Q3","week":1,"category":"Number and Algebra","topic":"number patterns","difficulty":"M","estSecs":70,"question":"A sequence begins 2, 5, 10, 17, 26, ... The gaps between terms grow by the same amount each time. What is the 7th term of the sequence?","options":{"A":"37","B":"42","C":"65","D":"48","E":"50"},"answer":"E","explanation":"The differences are 3, 5, 7, 9, ... increasing by 2 each time. So the next differences are 11 and 13. Continuing: 6th term = 26 + 11 = 37, 7th term = 37 + 13 = 50. (Equivalently each term is n x n + 1, and 7 x 7 + 1 = 50.)"},
  {"id":"NA-W1-Q4","week":1,"category":"Number and Algebra","topic":"working backwards","difficulty":"M","estSecs":70,"question":"I think of a number. I double it, then subtract 5, then divide the result by 3, and I get 7. What was my original number?","options":{"A":"8","B":"13","C":"16","D":"11","E":"26"},"answer":"B","explanation":"Work backwards from 7. Undo the division by 3: 7 x 3 = 21. Undo the subtraction of 5: 21 + 5 = 26. Undo the doubling: 26 / 2 = 13. Check: 13 x 2 = 26, 26 - 5 = 21, 21 / 3 = 7."},
  {"id":"NA-W1-Q5","week":1,"category":"Number and Algebra","topic":"divisibility and digit puzzles","difficulty":"M","estSecs":70,"question":"The three-digit number '4 _ 6' (with a missing middle digit) is divisible by both 3 and 4. What must the missing middle digit be?","options":{"A":"2","B":"3","C":"5","D":"8","E":"6"},"answer":"C","explanation":"For divisibility by 4, the last two digits (the middle digit followed by 6) must form a multiple of 4: 16, 36, 56, 76, 96 work, so the middle digit is odd. For divisibility by 3, the digit sum 4 + digit + 6 = 10 + digit must be a multiple of 3, giving digit = 2, 5, or 8. The only value that is both odd and gives a multiple of 3 is 5. The number is 456 (456 / 4 = 114 and 456 / 3 = 152)."},
  {"id":"NA-W1-Q6","week":1,"category":"Number and Algebra","topic":"rates","difficulty":"E","estSecs":45,"question":"Three identical taps, all running together, fill a pool in 8 hours. How long would it take four such taps, running together at the same rate, to fill the same pool?","options":{"A":"11 h","B":"8 h","C":"10 h 40 min","D":"24 h","E":"6 h"},"answer":"E","explanation":"The total work is 3 taps x 8 hours = 24 'tap-hours'. With 4 taps the time is 24 / 4 = 6 hours. More taps means less time (inverse proportion), so the answer must be less than 8 hours."},
  {"id":"NA-W1-Q7","week":1,"category":"Number and Algebra","topic":"simple algebra","difficulty":"M","estSecs":70,"question":"A pen costs $2 more than a pencil. Three pencils and two pens together cost $19. What is the cost of one pen?","options":{"A":"$3","B":"$7","C":"$4","D":"$5","E":"$2"},"answer":"D","explanation":"Let a pencil cost p dollars, so a pen costs p + 2. Then 3p + 2(p + 2) = 19, giving 3p + 2p + 4 = 19, so 5p = 15 and p = 3. A pencil is $3, so a pen is 3 + 2 = $5. Check: 3 x $3 + 2 x $5 = $9 + $10 = $19."},
  {"id":"NA-W2-Q1","week":2,"category":"Number and Algebra","topic":"ratios","difficulty":"M","estSecs":70,"question":"$180 is shared between Ann, Ben and Cara in the ratio 1 : 3 : 5 (Ann : Ben : Cara). How much more money does Cara receive than Ann?","options":{"A":"$80","B":"$60","C":"$100","D":"$20","E":"$120"},"answer":"A","explanation":"The total number of parts is 1 + 3 + 5 = 9, so each part is 180 / 9 = $20. Cara gets 5 parts = $100 and Ann gets 1 part = $20. Cara receives 100 - 20 = $80 more. (This equals the 4-part difference, 4 x $20 = $80.)"},
  {"id":"NA-W2-Q2","week":2,"category":"Number and Algebra","topic":"fractions of quantities","difficulty":"M","estSecs":70,"question":"Maya spent 1/3 of her money on a book. She then spent 1/4 of what was left on food. She has $18 remaining. How much money did she start with?","options":{"A":"$24","B":"$36","C":"$27","D":"$48","E":"$72"},"answer":"B","explanation":"After the book, 2/3 of the money remains. She spends 1/4 of that on food, leaving 3/4 of the remainder: 3/4 x 2/3 = 1/2 of the original amount. So 1/2 of the starting money = $18, meaning she started with $36. Check: book $12, remainder $24, food $6, left $18."},
  {"id":"NA-W2-Q3","week":2,"category":"Number and Algebra","topic":"number patterns","difficulty":"M","estSecs":70,"question":"Matchsticks are used to build a row of squares. Figure 1 uses 4 matchsticks, Figure 2 uses 7, Figure 3 uses 10, and so on, adding 3 each time. How many matchsticks are needed for Figure 20?","options":{"A":"58","B":"60","C":"61","D":"63","E":"64"},"answer":"C","explanation":"Each figure adds 3 matchsticks, so the count is 4 + 3 x (figure number - 1) = 3 x figure + 1. For Figure 20: 3 x 20 + 1 = 61. (A common error is 3 x 20 = 60, forgetting the extra starting stick.)"},
  {"id":"NA-W2-Q4","week":2,"category":"Number and Algebra","topic":"working backwards","difficulty":"M","estSecs":70,"question":"In 5 years' time, Tom will be exactly three times as old as he was 3 years ago. How old is Tom now?","options":{"A":"6","B":"9","C":"12","D":"4","E":"7"},"answer":"E","explanation":"Let Tom's age now be x. In 5 years he is x + 5; three years ago he was x - 3. The condition gives x + 5 = 3(x - 3), so x + 5 = 3x - 9, giving 14 = 2x and x = 7. Check: now 7, in 5 years 12, three years ago 4, and 3 x 4 = 12."},
  {"id":"NA-W2-Q5","week":2,"category":"Number and Algebra","topic":"divisibility and digit puzzles","difficulty":"H","estSecs":100,"question":"What is the smallest whole number greater than 1 that leaves a remainder of 1 when divided by each of 2, 3, 4, 5 and 6?","options":{"A":"61","B":"41","C":"60","D":"31","E":"121"},"answer":"A","explanation":"A number leaving remainder 1 when divided by all of these is 1 more than a common multiple of 2, 3, 4, 5 and 6. The smallest such common multiple (the LCM) is 60, so the number is 60 + 1 = 61. Check: 61 divided by 2, 3, 4, 5 or 6 each leaves remainder 1."},
  {"id":"NA-W2-Q6","week":2,"category":"Number and Algebra","topic":"rates","difficulty":"E","estSecs":45,"question":"A car travels 240 km using 20 litres of petrol. At the same rate of fuel use, how far can it travel on 35 litres?","options":{"A":"350 km","B":"400 km","C":"420 km","D":"360 km","E":"480 km"},"answer":"C","explanation":"The car travels 240 / 20 = 12 km per litre. On 35 litres it can travel 35 x 12 = 420 km."},
  {"id":"NA-W2-Q7","week":2,"category":"Number and Algebra","topic":"simple algebra","difficulty":"M","estSecs":70,"question":"The sum of three consecutive even numbers is 78. What is the largest of the three numbers?","options":{"A":"28","B":"25","C":"26","D":"24","E":"30"},"answer":"A","explanation":"Three consecutive even numbers can be written as (n - 2), n, (n + 2); their sum is 3n = 78, so the middle number n = 26. The three numbers are 24, 26, 28, and the largest is 28. Check: 24 + 26 + 28 = 78."},
  {"id":"NA-W3-Q1","week":3,"category":"Number and Algebra","topic":"proportion","difficulty":"E","estSecs":45,"question":"On a map, a scale of 1 cm represents 25 km. Two towns are drawn 6.4 cm apart on the map. What is the actual distance between the towns?","options":{"A":"156 km","B":"128 km","C":"160 km","D":"40 km","E":"200 km"},"answer":"C","explanation":"Each centimetre stands for 25 km, so 6.4 cm represents 6.4 x 25 = 160 km."},
  {"id":"NA-W3-Q2","week":3,"category":"Number and Algebra","topic":"fractions of quantities","difficulty":"M","estSecs":70,"question":"In a class, 2/5 of the students are boys and the rest are girls. There are 9 more girls than boys. How many students are in the class altogether?","options":{"A":"15","B":"90","C":"36","D":"27","E":"45"},"answer":"E","explanation":"Boys are 2/5 and girls are 3/5 of the class, so girls exceed boys by 3/5 - 2/5 = 1/5 of the class. This difference is 9 students, so 1/5 of the class = 9 and the whole class = 45. Check: boys 18, girls 27, difference 9."},
  {"id":"NA-W3-Q3","week":3,"category":"Number and Algebra","topic":"number patterns","difficulty":"M","estSecs":70,"question":"Consider the sequence of square numbers 1, 4, 9, 16, 25, ... What is the difference between the 10th term and the 8th term?","options":{"A":"4","B":"19","C":"20","D":"30","E":"36"},"answer":"E","explanation":"The nth term is n x n. The 10th term is 10 x 10 = 100 and the 8th term is 8 x 8 = 64. The difference is 100 - 64 = 36. (Using the 9th term, 81, by mistake gives 100 - 81 = 19.)"},
  {"id":"NA-W3-Q4","week":3,"category":"Number and Algebra","topic":"working backwards","difficulty":"M","estSecs":70,"question":"When a certain number is increased by one quarter of itself, the result is 45. What is the number?","options":{"A":"30","B":"33.75","C":"40","D":"36","E":"56.25"},"answer":"D","explanation":"The number plus 1/4 of itself is 5/4 of the number. So 5/4 x number = 45, giving number = 45 x 4 / 5 = 36. Check: 36 + 1/4 of 36 = 36 + 9 = 45."},
  {"id":"NA-W3-Q5","week":3,"category":"Number and Algebra","topic":"divisibility and digit puzzles","difficulty":"M","estSecs":70,"question":"The three-digit number '3 _ 5' (with a missing middle digit) is divisible by 9. What is the missing middle digit?","options":{"A":"0","B":"9","C":"4","D":"7","E":"1"},"answer":"E","explanation":"A number is divisible by 9 when its digit sum is a multiple of 9. Here the digit sum is 3 + digit + 5 = 8 + digit. The only single digit making 8 + digit a multiple of 9 is 1 (giving 9). The number is 315, and 315 / 9 = 35."},
  {"id":"NA-W3-Q6","week":3,"category":"Number and Algebra","topic":"rates","difficulty":"E","estSecs":45,"question":"Amy reads 15 pages in 20 minutes. Reading at the same steady rate, how many pages can she read in 1 hour and 20 minutes?","options":{"A":"45","B":"60","C":"40","D":"75","E":"80"},"answer":"B","explanation":"1 hour 20 minutes = 80 minutes, which is 80 / 20 = 4 lots of 20 minutes. In each 20-minute period she reads 15 pages, so she reads 4 x 15 = 60 pages."},
  {"id":"NA-W3-Q7","week":3,"category":"Number and Algebra","topic":"simple algebra","difficulty":"M","estSecs":70,"question":"Two apples and three bananas weigh 550 g. Two apples and five bananas weigh 750 g. All apples weigh the same, and all bananas weigh the same. What is the weight of one banana?","options":{"A":"50 g","B":"75 g","C":"100 g","D":"125 g","E":"150 g"},"answer":"C","explanation":"The two situations have the same 2 apples, but the second has 2 extra bananas and weighs 750 - 550 = 200 g more. So 2 bananas weigh 200 g, meaning one banana weighs 100 g. (Each apple would weigh 125 g.)"},
  {"id":"NA-W4-Q1","week":4,"category":"Number and Algebra","topic":"ratios","difficulty":"H","estSecs":100,"question":"A bag contains red and blue marbles in the ratio 3 : 2. After 10 more red marbles are added, the ratio of red to blue becomes 2 : 1. How many blue marbles are in the bag?","options":{"A":"30","B":"15","C":"10","D":"20","E":"40"},"answer":"D","explanation":"Let red = 3k and blue = 2k. After adding 10 reds: (3k + 10) / (2k) = 2 / 1, so 3k + 10 = 4k, giving k = 10. Blue = 2k = 20. Check: red 30, blue 20; after adding 10 reds it is 40 : 20 = 2 : 1."},
  {"id":"NA-W4-Q2","week":4,"category":"Number and Algebra","topic":"fractions of quantities","difficulty":"M","estSecs":70,"question":"Three eighths of a number is 21 more than one quarter of the same number. What is the number?","options":{"A":"42","B":"168","C":"84","D":"56","E":"336"},"answer":"B","explanation":"The difference 3/8 - 1/4 = 3/8 - 2/8 = 1/8 of the number equals 21. So the number is 8 x 21 = 168. Check: 3/8 of 168 = 63 and 1/4 of 168 = 42, and 63 - 42 = 21."},
  {"id":"NA-W4-Q3","week":4,"category":"Number and Algebra","topic":"number patterns","difficulty":"M","estSecs":70,"question":"In an arithmetic sequence (one that goes up by the same amount each step), the 3rd term is 14 and the 7th term is 34. What is the 1st term?","options":{"A":"4","B":"5","C":"2","D":"6","E":"9"},"answer":"A","explanation":"From the 3rd term to the 7th term is 4 steps, and the value rises by 34 - 14 = 20, so each step (common difference) is 20 / 4 = 5. Going back 2 steps from the 3rd term: 14 - 2 x 5 = 4."},
  {"id":"NA-W4-Q4","week":4,"category":"Number and Algebra","topic":"working backwards","difficulty":"H","estSecs":100,"question":"A stallholder sold half of his apples plus 2 more in the morning. In the afternoon he sold half of what was left plus 2 more. He then had 5 apples remaining. How many apples did he start with?","options":{"A":"16","B":"24","C":"32","D":"28","E":"40"},"answer":"C","explanation":"Work backwards from 5. Before selling '2 more' in the afternoon there were 5 + 2 = 7, and that 7 was half of the apples present at the start of the afternoon, so there were 14. Before the morning's '2 more', there were 14 + 2 = 16, and that 16 was half the starting amount, so he began with 32. Check: morning sells 18 (leaving 14), afternoon sells 9 (leaving 5)."},
  {"id":"NA-W4-Q5","week":4,"category":"Number and Algebra","topic":"divisibility and digit puzzles","difficulty":"M","estSecs":70,"question":"How many whole numbers from 1 to 100 inclusive are divisible by both 4 and 6?","options":{"A":"4","B":"6","C":"16","D":"8","E":"12"},"answer":"D","explanation":"A number divisible by both 4 and 6 must be a multiple of their lowest common multiple, which is 12. The multiples of 12 up to 100 are 12, 24, 36, 48, 60, 72, 84, 96 - that is 8 numbers."},
  {"id":"NA-W4-Q6","week":4,"category":"Number and Algebra","topic":"rates","difficulty":"E","estSecs":45,"question":"Printer A prints 12 pages per minute and Printer B prints 8 pages per minute. If both printers work together at the same time, how long will it take to print 300 pages?","options":{"A":"25 min","B":"12 min","C":"20 min","D":"15 min","E":"30 min"},"answer":"D","explanation":"Working together the printers produce 12 + 8 = 20 pages per minute. To print 300 pages takes 300 / 20 = 15 minutes."},
  {"id":"NA-W4-Q7","week":4,"category":"Number and Algebra","topic":"simple algebra","difficulty":"M","estSecs":70,"question":"At a cinema, a child's ticket costs $4 less than an adult's ticket. A family buys 2 adult tickets and 3 child tickets for a total of $53. What is the price of one adult ticket?","options":{"A":"$13","B":"$9","C":"$11","D":"$15","E":"$17"},"answer":"A","explanation":"Let an adult ticket cost a dollars, so a child ticket is a - 4. Then 2a + 3(a - 4) = 53, giving 2a + 3a - 12 = 53, so 5a = 65 and a = 13. An adult ticket is $13 (a child ticket is $9). Check: 2 x $13 + 3 x $9 = $26 + $27 = $53."},
  {"id":"MG-W1-Q1","week":1,"category":"Measurement and Geometry","topic":"composite area","difficulty":"M","estSecs":70,"question":"An L-shaped garden bed has straight sides that meet only at right angles. Starting at the top-left corner and walking clockwise around the edge, the side lengths in order are: 15 m (going right), 6 m (down), 9 m (left), 4 m (down), 6 m (left), and 10 m (up) back to the start. What is the total area of the garden bed?","options":{"A":"90 m²","B":"96 m²","C":"114 m²","D":"126 m²","E":"150 m²"},"answer":"C","explanation":"The path encloses a full bounding rectangle 15 m wide and 10 m tall (area 15 x 10 = 150 m²) with a rectangular bite removed from the bottom-right. That missing rectangle is 9 m wide (15 - 6) and 4 m tall, so its area is 9 x 4 = 36 m². The garden = 150 - 36 = 114 m². Check by splitting instead: a top strip 15 x 6 = 90 m² plus a bottom-left block 6 x 4 = 24 m² gives 90 + 24 = 114 m². (Option E is the whole bounding rectangle; A is only the top strip; D and B come from mis-sizing the removed or added piece.)"},
  {"id":"MG-W1-Q2","week":1,"category":"Measurement and Geometry","topic":"volume and capacity","difficulty":"M","estSecs":70,"question":"A rectangular fish tank has a base measuring 40 cm by 25 cm and is 30 cm tall. Water sits at a depth of 18 cm. A solid ornamental rock is placed on the bottom and fully submerged, and the water level rises to 22 cm. What is the volume of the rock?","options":{"A":"400 cm³","B":"4000 cm³","C":"18 000 cm³","D":"22 000 cm³","E":"40 000 cm³"},"answer":"B","explanation":"A fully submerged object pushes the water up by exactly its own volume. The water rose from 18 cm to 22 cm, a rise of 4 cm, spread over the tank's base area of 40 x 25 = 1000 cm². Volume of rock = base area x rise = 1000 x 4 = 4000 cm³. (Option C uses the old depth 18, D uses the new depth 22, A forgets the width, E fills the whole tank.)"},
  {"id":"MG-W1-Q3","week":1,"category":"Measurement and Geometry","topic":"angles","difficulty":"M","estSecs":70,"question":"The three angles of Triangle 1 are in the ratio 2 : 3 : 4. Triangle 2 is isosceles, and its apex (top) angle is equal to the smallest angle of Triangle 1. What is the size of EACH of the two equal base angles of Triangle 2?","options":{"A":"40°","B":"60°","C":"70°","D":"80°","E":"140°"},"answer":"C","explanation":"The ratio parts add to 2 + 3 + 4 = 9, and the angles of a triangle total 180°, so one part = 180 / 9 = 20°. Triangle 1's angles are 40°, 60° and 80°, so its smallest angle is 40°. This is the apex of the isosceles Triangle 2, leaving 180 - 40 = 140° to share between the two equal base angles: 140 / 2 = 70°. (A is the apex itself, E is the leftover before halving, D is Triangle 1's largest angle.)"},
  {"id":"MG-W1-Q4","week":1,"category":"Measurement and Geometry","topic":"cube counting","difficulty":"H","estSecs":100,"question":"A large cube measuring 5 units on each edge is painted on all six of its outer faces, then cut into 1-unit cubes (125 small cubes in total). How many of the small cubes have paint on exactly ONE face?","options":{"A":"8","B":"27","C":"36","D":"54","E":"98"},"answer":"D","explanation":"Cubes with exactly one painted face come from the middle of each large face, avoiding all the edges. On each 5x5 face, that inner block is (5 - 2) x (5 - 2) = 3 x 3 = 9 cubes. There are 6 faces, so 6 x 9 = 54. (B = 27 is the fully hidden interior cubes, C = 36 have exactly two painted faces (the edges), A = 8 are the corners with three faces, and E = 98 is every painted cube 125 - 27.)"},
  {"id":"MG-W1-Q5","week":1,"category":"Measurement and Geometry","topic":"transformations","difficulty":"M","estSecs":70,"question":"Point P is at coordinates (3, 1). P is first reflected in the y-axis. The resulting point is then rotated a quarter-turn (90°) CLOCKWISE about the origin (0, 0). What are the final coordinates?","options":{"A":"(-1, 3)","B":"(1, -3)","C":"(-1, -3)","D":"(1, 3)","E":"(3, -1)"},"answer":"D","explanation":"Reflecting (3, 1) in the y-axis flips the sign of the x-coordinate: (-3, 1). A 90° clockwise rotation about the origin sends (x, y) to (y, -x). So (-3, 1) becomes (1, -(-3)) = (1, 3). (Option C comes from doing the steps in the wrong order: rotate first to (1, -3), then reflect to (-1, -3). Others mix up the rotation rule.)"},
  {"id":"MG-W1-Q6","week":1,"category":"Measurement and Geometry","topic":"elapsed time","difficulty":"E","estSecs":45,"question":"A plane leaves Sydney at 11:45 pm on Monday. The flight takes 14 hours and 30 minutes. The destination city's local time is 5 hours BEHIND Sydney time. What is the local date and time at the destination when the plane lands?","options":{"A":"9:15 am Monday","B":"9:15 am Tuesday","C":"2:15 pm Tuesday","D":"7:15 pm Tuesday","E":"4:15 am Tuesday"},"answer":"B","explanation":"Add the flight time in Sydney time first: 11:45 pm Monday + 14 h = 1:45 pm Tuesday, then + 30 min = 2:15 pm Tuesday (Sydney time). The destination is 5 hours behind, so subtract 5 hours: 2:15 pm - 5 h = 9:15 am Tuesday. (C forgets the time-zone step; D adds 5 hours instead of subtracting.)"},
  {"id":"MG-W1-Q7","week":1,"category":"Measurement and Geometry","topic":"unit conversion","difficulty":"H","estSecs":100,"question":"A leaking tap drips 3 drops every 2 seconds. Each drop has a volume of 0.05 mL. How many LITRES of water leak away in one full day (24 hours)?","options":{"A":"0.648 L","B":"3.24 L","C":"6.48 L","D":"12.96 L","E":"64.8 L"},"answer":"C","explanation":"One day = 24 x 60 x 60 = 86 400 seconds. Drips come at 3 drops per 2 seconds, i.e. 1.5 drops per second, so total drops = 86 400 x 1.5 = 129 600 drops. Volume = 129 600 x 0.05 mL = 6480 mL. Since 1000 mL = 1 L, that is 6.48 L. (D = 12.96 L comes from wrongly using 3 drops every second; E = 64.8 L forgets to convert mL to L correctly.)"},
  {"id":"MG-W2-Q1","week":2,"category":"Measurement and Geometry","topic":"composite perimeter","difficulty":"H","estSecs":100,"question":"A shape is drawn like a staircase. It starts at the bottom-left corner, rises to the top-right corner using only right-angled steps, and never once goes left or downwards. All the horizontal parts of the staircase add up to 12 cm in length, and all the vertical parts add up to 9 cm. This staircase, together with a straight 12 cm bottom edge and a straight 9 cm left edge, encloses a region. What is the perimeter of the whole enclosed region?","options":{"A":"21 cm","B":"30 cm","C":"33 cm","D":"42 cm","E":"108 cm"},"answer":"D","explanation":"The staircase only ever moves right or up, so its horizontal pieces together span the full 12 cm width and its vertical pieces span the full 9 cm height; the total length of the staircase itself is 12 + 9 = 21 cm. The region is also bounded by the bottom edge (12 cm) and the left edge (9 cm). Perimeter = 21 + 12 + 9 = 42 cm. (A = 21 is only the staircase, B = 30 forgets the staircase counts, E = 108 mistakenly uses an area idea.)"},
  {"id":"MG-W2-Q2","week":2,"category":"Measurement and Geometry","topic":"volume and surface area","difficulty":"M","estSecs":70,"question":"A closed box is a rectangular prism with a SQUARE base. Its volume is 200 cm³ and its height is 8 cm. What is the total surface area of the box (all six faces)?","options":{"A":"90 cm²","B":"160 cm²","C":"210 cm²","D":"250 cm²","E":"130 cm²"},"answer":"C","explanation":"Volume = base area x height, so the square base area = 200 / 8 = 25 cm², giving a base side of the square root of 25 = 5 cm. The two square faces (top and bottom) contribute 2 x 25 = 50 cm². The four side faces each measure 5 x 8 = 40 cm², contributing 4 x 40 = 160 cm². Total surface area = 50 + 160 = 210 cm². (B = 160 counts only the sides, E = 130 uses only two side faces.)"},
  {"id":"MG-W2-Q3","week":2,"category":"Measurement and Geometry","topic":"polygon angles","difficulty":"H","estSecs":100,"question":"A regular polygon has each interior angle equal to 150°. A second regular polygon has exactly HALF as many sides as the first. What is the size of each interior angle of the second polygon?","options":{"A":"60°","B":"108°","C":"120°","D":"135°","E":"144°"},"answer":"C","explanation":"For the first polygon, each exterior angle = 180° - 150° = 30°. Exterior angles of any polygon add to 360°, so the number of sides = 360 / 30 = 12. Half of 12 is 6 sides (a regular hexagon). A hexagon's interior angle = (6 - 2) x 180 / 6 = 720 / 6 = 120°. (B = 108° is a pentagon, E = 144° is a decagon, D = 135° is an octagon.)"},
  {"id":"MG-W2-Q4","week":2,"category":"Measurement and Geometry","topic":"nets of a cube","difficulty":"H","estSecs":100,"question":"A flat net of a cube is laid out. Four squares sit in a horizontal row, labelled 1, 2, 3, 4 from left to right. One extra square, labelled 5, is attached to the TOP edge of square 2, and another square, labelled 6, is attached to the BOTTOM edge of square 2. When this net is folded into a cube, which face ends up directly OPPOSITE face 3?","options":{"A":"1","B":"2","C":"4","D":"5","E":"6"},"answer":"A","explanation":"Treat square 2 as the front face. Then square 1 (to its left) folds to the left face, square 3 (to its right) folds to the right face, square 5 (above) becomes the top, and square 6 (below) becomes the bottom. Square 4 is beyond square 3, so it wraps around to become the back face (opposite the front, square 2). The opposite pairs are 2-4, 5-6, and 1-3. So the face opposite 3 is face 1. (D and E are the top/bottom, C is opposite face 2.)"},
  {"id":"MG-W2-Q5","week":2,"category":"Measurement and Geometry","topic":"rotational symmetry","difficulty":"M","estSecs":70,"question":"Consider these seven capital letters printed in a plain upright font: H, N, S, Z, X, O, E. How many of them look exactly the same after being rotated by a half-turn (180°)?","options":{"A":"4","B":"5","C":"6","D":"7","E":"3"},"answer":"C","explanation":"Rotate each letter 180° about its centre. H -> H (same), N -> N (same), S -> S (same), Z -> Z (same), X -> X (same), O -> O (same). Only E fails: a half-turn would put its bars on the wrong side, so it does not match. That gives 6 letters with rotational symmetry of order 2. (Choosing 7 wrongly includes E.)"},
  {"id":"MG-W2-Q6","week":2,"category":"Measurement and Geometry","topic":"elapsed time","difficulty":"M","estSecs":70,"question":"A faulty clock loses 3 minutes for every hour of real time that passes. It is set to show exactly the correct time at 12:00 noon. What time will the faulty clock display when the true time is 12:00 midnight the same day?","options":{"A":"11:24 pm","B":"11:36 pm","C":"11:57 pm","D":"12:24 am","E":"12:36 am"},"answer":"A","explanation":"From noon to midnight is 12 real hours. The clock loses 3 minutes each hour, so it falls behind by 3 x 12 = 36 minutes over that time. When the true time is midnight (12:00 am), the faulty clock reads 36 minutes earlier: 12:00 midnight - 36 minutes = 11:24 pm. (C = 11:57 pm loses only 3 minutes total; D/E add time instead of losing it.)"},
  {"id":"MG-W2-Q7","week":2,"category":"Measurement and Geometry","topic":"unit conversion","difficulty":"M","estSecs":70,"question":"A muffin recipe uses 250 mL of milk to make one batch of 12 muffins. Milk is sold only in 1-litre cartons. A baker needs to make 300 muffins for a fete. What is the smallest number of whole cartons of milk she must buy?","options":{"A":"6","B":"7","C":"8","D":"12","E":"25"},"answer":"B","explanation":"300 muffins / 12 muffins per batch = 25 batches. Milk needed = 25 x 250 mL = 6250 mL = 6.25 L. Each carton holds 1 L, so 6 cartons (6 L) is not enough; she must round UP to 7 cartons. (A = 6 wrongly rounds down, E = 25 is the number of batches, D = 12 is muffins per batch.)"},
  {"id":"MG-W3-Q1","week":3,"category":"Measurement and Geometry","topic":"composite area","difficulty":"M","estSecs":70,"question":"A square sheet of paper has sides of 20 cm. Each of the four corners is folded inwards so that the corner point lands exactly on the centre of the square. This creates a smaller square in the middle whose corners are the midpoints of the original sides. What is the area of that smaller middle square?","options":{"A":"50 cm²","B":"100 cm²","C":"141 cm²","D":"200 cm²","E":"400 cm²"},"answer":"D","explanation":"The smaller square joins the midpoints of the big square's sides, so its diagonal equals the big square's side, 20 cm. A square with diagonal d has area d² / 2 = 20² / 2 = 400 / 2 = 200 cm². Another way: the four folded corner triangles together exactly cover half the paper, so the middle square is the other half: 400 / 2 = 200 cm². (E is the whole sheet, B halves the side not the area, C mistakes a side length for an area.)"},
  {"id":"MG-W3-Q2","week":3,"category":"Measurement and Geometry","topic":"capacity and rate","difficulty":"M","estSecs":70,"question":"An empty tank is a rectangular prism measuring 50 cm long, 30 cm wide and 40 cm high. Water pours in at 6 litres per minute, but a crack lets water leak OUT at 2 litres per minute. How long will it take to fill the tank completely to the top?","options":{"A":"8 minutes","B":"10 minutes","C":"12 minutes","D":"15 minutes","E":"30 minutes"},"answer":"D","explanation":"Tank volume = 50 x 30 x 40 = 60 000 cm³. Since 1000 cm³ = 1 litre, that is 60 litres. The net filling rate = 6 - 2 = 4 litres per minute. Time = 60 / 4 = 15 minutes. (B = 10 ignores the leak, E = 30 uses only the leak rate.)"},
  {"id":"MG-W3-Q3","week":3,"category":"Measurement and Geometry","topic":"clock angles","difficulty":"H","estSecs":100,"question":"What is the size of the angle between the hour hand and the minute hand of an ordinary clock at exactly 3:40?","options":{"A":"110°","B":"120°","C":"130°","D":"140°","E":"150°"},"answer":"C","explanation":"The minute hand at 40 minutes points at the 8, which is 40 x 6 = 240° clockwise from 12 (each minute = 6°). The hour hand moves 30° per hour plus 0.5° per minute, so at 3:40 it is at 3 x 30 + 40 x 0.5 = 90 + 20 = 110°. The angle between them = 240 - 110 = 130°. (A = 110° forgets to compare to the minute hand; E = 150° ignores the hour hand's extra 20° of movement.)"},
  {"id":"MG-W3-Q4","week":3,"category":"Measurement and Geometry","topic":"cross-sections","difficulty":"H","estSecs":100,"question":"A wooden cube has one of its corners sliced off with a single straight (flat) cut. The cut passes exactly through the three vertices that are nearest to that corner (one along each of the three edges meeting there). What is the shape of the flat face that is newly exposed by the cut?","options":{"A":"a square","B":"a rectangle","C":"a right-angled triangle","D":"an equilateral triangle","E":"a regular hexagon"},"answer":"D","explanation":"The three cut vertices are the corners next to the chosen corner. Each side of the exposed triangle is a diagonal of one of the cube's square faces, and all faces of a cube are identical squares, so all three face-diagonals are equal in length. A triangle with three equal sides is equilateral. (A right-angled triangle would need the cut to pass along edges, not across face diagonals; a hexagon comes from cutting through the middle of the cube, not a corner.)"},
  {"id":"MG-W3-Q5","week":3,"category":"Measurement and Geometry","topic":"transformations","difficulty":"M","estSecs":70,"question":"A triangle has vertices at (1, 1), (4, 1) and (1, 5). The whole triangle is first translated 3 units to the right and 2 units up. It is then reflected in the x-axis. What are the final coordinates of the image of the vertex that started at (1, 5)?","options":{"A":"(4, 7)","B":"(4, -7)","C":"(-4, 7)","D":"(-4, -7)","E":"(7, -4)"},"answer":"B","explanation":"Translate (1, 5) by 3 right and 2 up: add 3 to x and 2 to y, giving (4, 7). Reflecting in the x-axis keeps x the same and flips the sign of y, so (4, 7) becomes (4, -7). (A forgets the reflection; C/D wrongly flip the x-coordinate; E swaps the coordinates.)"},
  {"id":"MG-W3-Q6","week":3,"category":"Measurement and Geometry","topic":"elapsed time","difficulty":"M","estSecs":70,"question":"A movie marathon shows three films lasting 1 h 55 min, 2 h 10 min and 1 h 40 min. Between consecutive films there are two breaks, each 25 minutes long. If the marathon begins at 6:20 pm, at what time does it finish?","options":{"A":"11:45 pm","B":"12:05 am","C":"12:55 am","D":"1:05 am","E":"1:20 am"},"answer":"C","explanation":"Total film time: 1 h 55 + 2 h 10 = 4 h 05; plus 1 h 40 = 5 h 45. Breaks: 2 x 25 min = 50 min. Total running time = 5 h 45 + 50 min = 6 h 35 min. Starting at 6:20 pm: 6:20 pm + 6 h = 12:20 am, then + 35 min = 12:55 am. (B = 12:05 am forgets the two breaks; E = 1:20 am adds too much.)"},
  {"id":"MG-W3-Q7","week":3,"category":"Measurement and Geometry","topic":"scale and area","difficulty":"M","estSecs":70,"question":"On a map, a distance of 2 cm represents 5 km in real life. A rectangular national park is drawn on the map as a rectangle measuring 8 cm by 6 cm. What is the actual area of the park?","options":{"A":"48 km²","B":"120 km²","C":"300 km²","D":"600 km²","E":"1200 km²"},"answer":"C","explanation":"The scale means 1 cm represents 5 / 2 = 2.5 km. So 8 cm is 8 x 2.5 = 20 km and 6 cm is 6 x 2.5 = 15 km. The real park is 20 km by 15 km, giving an area of 20 x 15 = 300 km². (A = 48 is the map area in cm², B = 120 multiplies the map area by the scale only once instead of converting each side.)"},
  {"id":"MG-W4-Q1","week":4,"category":"Measurement and Geometry","topic":"composite area","difficulty":"M","estSecs":70,"question":"A square has sides of 10 cm. From each of its four corners an identical right-angled triangle is cut away, each triangle having legs of 3 cm and 7 cm (the 3 cm and 7 cm legs lie along the square's edges, and because 3 + 7 = 10 the cuts meet neatly). Removing the four triangles leaves a tilted square in the middle. What is the area of that middle tilted square?","options":{"A":"21 cm²","B":"42 cm²","C":"58 cm²","D":"79 cm²","E":"100 cm²"},"answer":"C","explanation":"The big square has area 10 x 10 = 100 cm². Each corner triangle has area 1/2 x 3 x 7 = 10.5 cm², and four of them total 4 x 10.5 = 42 cm². The middle tilted square is what remains: 100 - 42 = 58 cm². (You can check: each side of the middle square is the hypotenuse, length the square root of (3² + 7²) = square root of 58, so its area is 58 cm².) (B = 42 is the removed triangles, E = 100 is the whole square.)"},
  {"id":"MG-W4-Q2","week":4,"category":"Measurement and Geometry","topic":"volume","difficulty":"M","estSecs":70,"question":"A solid metal cube with an edge length of 6 cm is melted down and recast, with no metal wasted, into small rectangular bars each measuring 2 cm by 2 cm by 3 cm. How many complete bars can be made?","options":{"A":"9","B":"12","C":"18","D":"27","E":"36"},"answer":"C","explanation":"Volume of the cube = 6 x 6 x 6 = 216 cm³. Volume of one bar = 2 x 2 x 3 = 12 cm³. Number of bars = 216 / 12 = 18. (D = 27 would be the count if recast into 2 cm cubes, B = 12 divides by an edge instead of the bar volume.)"},
  {"id":"MG-W4-Q3","week":4,"category":"Measurement and Geometry","topic":"angles","difficulty":"M","estSecs":70,"question":"Two angles are supplementary (they add to 180°). One of the angles is 30° more than four times the size of the other. What is the size of the LARGER angle?","options":{"A":"30°","B":"78°","C":"120°","D":"138°","E":"150°"},"answer":"E","explanation":"Let the smaller angle be x. The other is 4x + 30. They are supplementary, so x + (4x + 30) = 180, giving 5x + 30 = 180, so 5x = 150 and x = 30°. The larger angle = 4 x 30 + 30 = 150°. Check: 30 + 150 = 180°. (A = 30° is the smaller angle; B = 78° comes from wrongly using complementary angles adding to 90°.)"},
  {"id":"MG-W4-Q4","week":4,"category":"Measurement and Geometry","topic":"spatial reasoning","difficulty":"H","estSecs":100,"question":"A cube is built from 27 unit cubes stacked in a 3 by 3 by 3 arrangement. A straight square tunnel (1 unit by 1 unit) is drilled right through the centre of the cube from front to back, another from left to right, and another from top to bottom - three tunnels, all passing through the very middle. How many of the 27 unit cubes are removed altogether?","options":{"A":"6","B":"7","C":"9","D":"20","E":"27"},"answer":"B","explanation":"Each tunnel removes a straight line of 3 unit cubes through the centre, so it looks like 3 x 3 = 9 cubes. But all three tunnels pass through the single centre cube, which would otherwise be counted three times. Removing the double-counting: the centre cube (1) plus two 'arm' cubes for each of the three directions (3 x 2 = 6) gives 1 + 6 = 7 distinct cubes removed. (C = 9 ignores the shared centre, D = 20 is the number of cubes left.)"},
  {"id":"MG-W4-Q5","week":4,"category":"Measurement and Geometry","topic":"folding and symmetry","difficulty":"M","estSecs":70,"question":"A square sheet of paper is folded exactly in half, then in half again, then in half a third time (three folds in total), each time doubling the number of layers. A single hole is then punched straight through all the layers at once. When the paper is completely unfolded, how many holes are in it?","options":{"A":"3","B":"4","C":"6","D":"8","E":"16"},"answer":"D","explanation":"Each fold doubles the number of layers of paper. After three folds there are 2 x 2 x 2 = 8 layers stacked together. One punch goes through all 8 layers, making 8 separate holes when unfolded. (A = 3 counts the folds rather than the layers; E = 16 would need a fourth fold.)"},
  {"id":"MG-W4-Q6","week":4,"category":"Measurement and Geometry","topic":"calendar time","difficulty":"H","estSecs":100,"question":"The 1st of January 2025 falls on a Wednesday. The year 2025 is NOT a leap year, so February has 28 days. On what day of the week does the 1st of March 2025 fall?","options":{"A":"Saturday","B":"Friday","C":"Thursday","D":"Sunday","E":"Monday"},"answer":"A","explanation":"From 1 January to 1 March is January's 31 days plus February's 28 days = 59 days later. Dividing 59 by 7 gives 8 weeks and 3 days left over (8 x 7 = 56, remainder 3). Counting 3 days on from Wednesday: Thursday, Friday, Saturday. So 1 March 2025 is a Saturday. (Forgetting that February has 28 days, or miscounting the remainder, leads to the neighbouring days.)"},
  {"id":"MG-W4-Q7","week":4,"category":"Measurement and Geometry","topic":"unit conversion and speed","difficulty":"M","estSecs":70,"question":"A car travels at a steady speed of 72 kilometres per hour. How many metres does it travel in 45 seconds?","options":{"A":"450 m","B":"900 m","C":"1080 m","D":"3240 m","E":"5400 m"},"answer":"B","explanation":"Convert the speed to metres per second: 72 km = 72 000 m and 1 hour = 3600 s, so 72 km/h = 72 000 / 3600 = 20 m/s. In 45 seconds the car travels 20 x 45 = 900 m. (D = 3240 wrongly multiplies 72 by 45; A = 450 uses half the correct speed.)"},
  {"id":"SP-W1-Q1","week":1,"category":"Statistics and Probability","topic":"averages backwards","difficulty":"M","estSecs":70,"question":"The average (mean) of six numbers is 15. One of the numbers is removed, and the average of the five numbers that remain is 13. What was the number that was removed?","options":{"A":"2","B":"13","C":"30","D":"15","E":"25"},"answer":"E","explanation":"The sum of the six numbers is 6 x 15 = 90. After removing one number, the five remaining numbers have a mean of 13, so their sum is 5 x 13 = 65. The removed number is the difference between the two sums: 90 - 65 = 25. (Choosing 2 mistakes the difference of the two averages for the answer; 13 and 15 are the averages themselves.)"},
  {"id":"SP-W1-Q2","week":1,"category":"Statistics and Probability","topic":"single-event probability","difficulty":"E","estSecs":45,"question":"A bag contains 4 red marbles, 6 blue marbles and 5 green marbles. One marble is drawn at random. What is the probability that the marble is NOT blue?","options":{"A":"3/5","B":"1/3","C":"2/3","D":"2/5","E":"11/15"},"answer":"A","explanation":"There are 4 + 6 + 5 = 15 marbles in total. 'Not blue' means red or green: 4 + 5 = 9 marbles. So the probability is 9/15, which simplifies to 3/5. (2/5 is the probability of blue itself; 11/15 comes from wrongly counting 'not red'.)"},
  {"id":"SP-W1-Q3","week":1,"category":"Statistics and Probability","topic":"systematic counting","difficulty":"M","estSecs":70,"question":"Using only the digits 3, 5, 7 and 8, and never repeating a digit within a number, how many different two-digit numbers can be formed?","options":{"A":"8","B":"24","C":"16","D":"20","E":"12"},"answer":"E","explanation":"There are 4 choices for the tens digit. Because no digit may be repeated, only 3 digits remain for the units place. The number of two-digit numbers is 4 x 3 = 12. (16 = 4 x 4 wrongly allows repeats; 24 = 4 x 3 x 2 counts three-digit numbers.)"},
  {"id":"SP-W1-Q4","week":1,"category":"Statistics and Probability","topic":"combined independent events","difficulty":"M","estSecs":70,"question":"A fair coin is tossed and a fair six-sided die (faces 1 to 6) is rolled. What is the probability of getting heads on the coin AND an even number on the die?","options":{"A":"1/4","B":"1/6","C":"1/12","D":"1/3","E":"1/2"},"answer":"A","explanation":"P(heads) = 1/2. The even numbers are 2, 4, 6, so P(even) = 3/6 = 1/2. The two events are independent, so multiply: 1/2 x 1/2 = 1/4. (1/12 comes from using 1/6 for a single die face instead of 1/2 for an even number.)"},
  {"id":"SP-W1-Q5","week":1,"category":"Statistics and Probability","topic":"median and mean combined","difficulty":"H","estSecs":100,"question":"Five different whole numbers are written in increasing order. The two smallest are 3 and 5, the median is 8, and the largest is 15. The fourth number lies between 8 and 15. If the mean of all five numbers is 9, what is the fourth number?","options":{"A":"10","B":"12","C":"13","D":"14","E":"19"},"answer":"D","explanation":"The five numbers in order are 3, 5, 8, ?, 15 (the median of five numbers is the middle one, which is 8). The mean is 9, so the total is 5 x 9 = 45. The four known numbers add to 3 + 5 + 8 + 15 = 31, so the fourth number is 45 - 31 = 14. This lies between 8 and 15, so it is valid."},
  {"id":"SP-W1-Q6","week":1,"category":"Statistics and Probability","topic":"mode and mean combined","difficulty":"M","estSecs":70,"question":"A set of seven numbers has a mode of 6, and 6 appears exactly three times. The other four numbers are all different from one another and from 6. Three of these four are 2, 4 and 10. If the mean of all seven numbers is 6, what is the remaining number?","options":{"A":"6","B":"9","C":"8","D":"10","E":"12"},"answer":"C","explanation":"The mean is 6, so the total of the seven numbers is 7 x 6 = 42. The three 6s contribute 18, and 2 + 4 + 10 = 16, giving 34 so far. The remaining number is 42 - 34 = 8. This is different from the others and does not repeat, so 6 stays the mode."},
  {"id":"SP-W1-Q7","week":1,"category":"Statistics and Probability","topic":"comparing likelihoods","difficulty":"M","estSecs":70,"question":"Spinner A has 3 equal sections numbered 1, 2, 3. Spinner B has 4 equal sections numbered 1, 2, 3, 4. Both spinners are spun once and the two numbers are added. Which statement is correct?","options":{"A":"A sum of 5 is more likely than a sum of 4","B":"A sum of 4 is more likely than a sum of 5","C":"A sum of 4 and a sum of 5 are equally likely, each with probability 1/3","D":"A sum of 5 is impossible","E":"A sum of 4 and a sum of 5 are equally likely, each with probability 1/4"},"answer":"E","explanation":"There are 3 x 4 = 12 equally likely outcomes. Pairs (A, B) giving a sum of 4: (1,3), (2,2), (3,1) - that is 3 outcomes. Pairs giving a sum of 5: (1,4), (2,3), (3,2) - also 3 outcomes. Both probabilities are 3/12 = 1/4, so the two sums are equally likely."},
  {"id":"SP-W2-Q1","week":2,"category":"Statistics and Probability","topic":"averages backwards","difficulty":"M","estSecs":70,"question":"A student's mean mark over 4 tests is 72. The student then sits a fifth test. What mark on the fifth test would raise the mean of all 5 tests to exactly 75?","options":{"A":"78","B":"84","C":"90","D":"87","E":"93"},"answer":"D","explanation":"The total over 4 tests is 4 x 72 = 288. To have a mean of 75 over 5 tests, the total must be 5 x 75 = 375. The fifth mark must be 375 - 288 = 87. (78 wrongly just adds 3, the change in the mean, to the fifth test only.)"},
  {"id":"SP-W2-Q2","week":2,"category":"Statistics and Probability","topic":"probability without replacement","difficulty":"H","estSecs":100,"question":"A drawer holds 3 black socks and 2 white socks. Two socks are pulled out one at a time, at random, without replacing the first. What is the probability that both socks are black?","options":{"A":"1/4","B":"2/5","C":"9/25","D":"1/2","E":"3/10"},"answer":"E","explanation":"The probability the first sock is black is 3/5. After removing one black sock, 2 black remain out of 4 socks, so the second is black with probability 2/4. Multiply: 3/5 x 2/4 = 6/20 = 3/10. (9/25 = 3/5 x 3/5 wrongly assumes replacement.)"},
  {"id":"SP-W2-Q3","week":2,"category":"Statistics and Probability","topic":"combinations","difficulty":"M","estSecs":70,"question":"A pizza shop offers 5 different toppings. How many different pizzas can be made using exactly 2 different toppings (a pizza with cheese and ham is the same as one with ham and cheese)?","options":{"A":"7","B":"25","C":"15","D":"10","E":"20"},"answer":"D","explanation":"Order does not matter. Counting ordered pairs gives 5 x 4 = 20, but each pair of toppings is counted twice (e.g. ham-cheese and cheese-ham), so divide by 2: 20 / 2 = 10. (20 forgets to divide; 25 = 5 x 5 allows a topping to pair with itself.)"},
  {"id":"SP-W2-Q4","week":2,"category":"Statistics and Probability","topic":"systematic counting","difficulty":"M","estSecs":70,"question":"At a small gathering, every person shakes hands with every other person exactly once. If there are 6 people, how many handshakes take place in total?","options":{"A":"30","B":"12","C":"21","D":"15","E":"36"},"answer":"D","explanation":"Each of the 6 people shakes hands with 5 others, giving 6 x 5 = 30, but this counts every handshake twice (once for each person). So divide by 2: 30 / 2 = 15. (30 forgets to halve; 36 = 6 x 6.)"},
  {"id":"SP-W2-Q5","week":2,"category":"Statistics and Probability","topic":"effect of adding a value on the mean","difficulty":"M","estSecs":70,"question":"The mean of a set of 9 numbers is 20. A tenth number is added to the set and the new mean of all 10 numbers becomes 22. What is the tenth number?","options":{"A":"22","B":"24","C":"38","D":"40","E":"42"},"answer":"D","explanation":"The 9 numbers total 9 x 20 = 180. With the tenth number, the 10 numbers must total 10 x 22 = 220. So the tenth number is 220 - 180 = 40. (22 is just the new mean; 24 wrongly adds only twice the change.)"},
  {"id":"SP-W2-Q6","week":2,"category":"Statistics and Probability","topic":"median with even count","difficulty":"H","estSecs":100,"question":"Six numbers are written in increasing order. Their median is 11 and their mean is 12. The third number is 9, and the two smallest numbers add to 10. What is the sum of the two largest numbers?","options":{"A":"30","B":"42","C":"50","D":"44","E":"40"},"answer":"E","explanation":"The median of six numbers is the average of the 3rd and 4th, so (9 + 4th)/2 = 11, giving a 4th number of 13; the 3rd and 4th together are 9 + 13 = 22. The total of all six is 6 x 12 = 72. The first two add to 10, so the last two are 72 - 10 - 22 = 40."},
  {"id":"SP-W2-Q7","week":2,"category":"Statistics and Probability","topic":"comparing likelihoods","difficulty":"M","estSecs":70,"question":"A bag holds 10 tickets numbered 1 to 10. One ticket is drawn at random. Event X: the number is a multiple of 3. Event Y: the number is even. Which event is more likely, and by how much?","options":{"A":"X is more likely, by 1/5","B":"They are equally likely","C":"Y is more likely, by 1/2","D":"Y is more likely, by 1/5","E":"Y is more likely, by 2/5"},"answer":"D","explanation":"Multiples of 3 are 3, 6, 9, so P(X) = 3/10. Even numbers are 2, 4, 6, 8, 10, so P(Y) = 5/10. Y is more likely, and the difference is 5/10 - 3/10 = 2/10 = 1/5."},
  {"id":"SP-W3-Q1","week":3,"category":"Statistics and Probability","topic":"averages backwards","difficulty":"E","estSecs":45,"question":"Five consecutive whole numbers have an average (mean) of 32. What is the largest of the five numbers?","options":{"A":"34","B":"33","C":"32","D":"35","E":"36"},"answer":"A","explanation":"For an odd number of consecutive whole numbers, the mean equals the middle number, so the middle number is 32. The five numbers are 30, 31, 32, 33, 34, and the largest is 34. (Choosing 36 wrongly adds 4 instead of 2 to the middle value.)"},
  {"id":"SP-W3-Q2","week":3,"category":"Statistics and Probability","topic":"combined events","difficulty":"H","estSecs":100,"question":"A fair coin is flipped 3 times. What is the probability of getting at least one head?","options":{"A":"1/8","B":"3/8","C":"7/8","D":"1/2","E":"3/4"},"answer":"C","explanation":"It is easier to find the opposite event. The only way to get no heads at all is tails, tails, tails, with probability 1/2 x 1/2 x 1/2 = 1/8. So P(at least one head) = 1 - 1/8 = 7/8. (1/8 is the probability of no heads; 3/8 counts exactly one head.)"},
  {"id":"SP-W3-Q3","week":3,"category":"Statistics and Probability","topic":"systematic counting with a constraint","difficulty":"M","estSecs":70,"question":"How many different three-digit numbers can be formed using the digits 1, 2, 3, 4 and 5, with no digit repeated, so that the number is even?","options":{"A":"12","B":"20","C":"60","D":"48","E":"24"},"answer":"E","explanation":"For an even number the units digit must be 2 or 4, giving 2 choices. After fixing the units digit, 4 digits remain for the hundreds place and then 3 for the tens place. Total = 2 x 4 x 3 = 24. (60 = 5 x 4 x 3 counts all three-digit numbers, ignoring the 'even' condition.)"},
  {"id":"SP-W3-Q4","week":3,"category":"Statistics and Probability","topic":"combined events","difficulty":"H","estSecs":100,"question":"Two fair six-sided dice are rolled. What is the probability that the product of the two numbers showing is odd?","options":{"A":"1/6","B":"1/4","C":"1/3","D":"1/2","E":"3/4"},"answer":"B","explanation":"A product is odd only when both numbers are odd (if either is even, the product is even). Each die shows an odd number (1, 3, 5) with probability 3/6 = 1/2. So P(both odd) = 1/2 x 1/2 = 1/4. (1/2 wrongly gives the chance a single die is odd.)"},
  {"id":"SP-W3-Q5","week":3,"category":"Statistics and Probability","topic":"weighted mean of two groups","difficulty":"H","estSecs":100,"question":"Class A has 20 students with an average test score of 15. Class B has 30 students with an average test score of 25. What is the average score of all 50 students combined?","options":{"A":"19","B":"20","C":"21","D":"22","E":"23"},"answer":"C","explanation":"Class A's total is 20 x 15 = 300 and Class B's total is 30 x 25 = 750. The combined total is 300 + 750 = 1050 across 50 students, so the mean is 1050 / 50 = 21. (20 comes from wrongly averaging the two class means, which ignores the different class sizes.)"},
  {"id":"SP-W3-Q6","week":3,"category":"Statistics and Probability","topic":"effect of changing a value","difficulty":"H","estSecs":100,"question":"A set of five numbers is 4, 7, 7, 10, 12. Exactly one number is to be changed so that the mean increases by 2 while the median stays the same. Which single change achieves this?","options":{"A":"Change the 12 to 22","B":"Change a 7 to 17","C":"Change the 4 to 14","D":"Change the 10 to 15","E":"Change the 12 to 17"},"answer":"A","explanation":"The current mean is (4+7+7+10+12)/5 = 40/5 = 8 and the median (middle value) is 7. A mean of 10 needs a total of 50, an increase of 10. Option A gives 4, 7, 7, 10, 22: the total is 50 (mean 10) and the sorted middle value is still 7. Options B and C increase a small value enough to push the median up to 10; options D and E raise the total by only 5, so the mean rises by just 1."},
  {"id":"SP-W3-Q7","week":3,"category":"Statistics and Probability","topic":"probability from overlapping sets","difficulty":"M","estSecs":70,"question":"In a class, 12 students play soccer, 8 play tennis, and 5 play both sports. A student is chosen at random from those who play at least one of these two sports. What is the probability that the chosen student plays tennis?","options":{"A":"1/3","B":"2/5","C":"1/2","D":"8/25","E":"8/15"},"answer":"E","explanation":"The number who play at least one sport is 12 + 8 - 5 = 15 (subtracting the 5 counted in both). The number who play tennis is 8. So the probability is 8/15. (8/25 comes from adding 12 + 8 + 5 = 25; 2/5 = 8/20 comes from double-counting the overlap in the total.)"},
  {"id":"SP-W4-Q1","week":4,"category":"Statistics and Probability","topic":"averages backwards","difficulty":"M","estSecs":70,"question":"The mean of 8 numbers is 18. Two of the numbers, 24 and 30, are removed from the set. What is the mean of the 6 numbers that remain?","options":{"A":"12","B":"14","C":"16","D":"18","E":"15"},"answer":"E","explanation":"The total of the 8 numbers is 8 x 18 = 144. Removing 24 and 30 subtracts 54, leaving a total of 144 - 54 = 90 across 6 numbers. The new mean is 90 / 6 = 15. (18 wrongly assumes the mean is unchanged.)"},
  {"id":"SP-W4-Q2","week":4,"category":"Statistics and Probability","topic":"probability without replacement","difficulty":"H","estSecs":100,"question":"A box contains 5 red balls and 3 blue balls. Two balls are drawn at random, one after the other, without replacement. What is the probability that the two balls are different colours?","options":{"A":"15/56","B":"15/32","C":"13/28","D":"1/2","E":"15/28"},"answer":"E","explanation":"Different colours can happen as red-then-blue or blue-then-red. P(red then blue) = 5/8 x 3/7 = 15/56, and P(blue then red) = 3/8 x 5/7 = 15/56. Adding both orders: 15/56 + 15/56 = 30/56 = 15/28. (15/56 counts only one order; 15/32 wrongly assumes replacement.)"},
  {"id":"SP-W4-Q3","week":4,"category":"Statistics and Probability","topic":"systematic counting","difficulty":"M","estSecs":70,"question":"Using only 5-cent, 10-cent and 20-cent coins, in how many different ways can you make exactly 30 cents? (The order of coins does not matter, and you may use none of a particular coin.)","options":{"A":"6","B":"5","C":"4","D":"7","E":"8"},"answer":"A","explanation":"List by the number of 20c coins. With no 20c coin, 30c from 5c and 10c: (6 fives), (4 fives + 1 ten), (2 fives + 2 tens), (3 tens) - that is 4 ways. With one 20c coin, the remaining 10c: (2 fives), (1 ten) - that is 2 ways. Total = 4 + 2 = 6 ways."},
  {"id":"SP-W4-Q4","week":4,"category":"Statistics and Probability","topic":"combined events","difficulty":"H","estSecs":100,"question":"Three friends each independently pick a number at random from 1 to 4. What is the probability that at least two of them pick the same number?","options":{"A":"3/8","B":"3/4","C":"1/2","D":"5/8","E":"5/16"},"answer":"D","explanation":"There are 4 x 4 x 4 = 64 equally likely outcomes. The opposite event is 'all three different': 4 choices for the first, 3 for the second, 2 for the third, giving 4 x 3 x 2 = 24. So P(at least two the same) = (64 - 24)/64 = 40/64 = 5/8. (3/8 = 24/64 is the probability that all three are different.)"},
  {"id":"SP-W4-Q5","week":4,"category":"Statistics and Probability","topic":"averages backwards","difficulty":"M","estSecs":70,"question":"The average age of a family of 5 people is 28 years. The youngest child is 4 years old. If the youngest child is not counted, what is the average age of the other 4 family members?","options":{"A":"24","B":"32","C":"36","D":"35","E":"34"},"answer":"E","explanation":"The total age of all 5 people is 5 x 28 = 140 years. Removing the youngest child's age gives 140 - 4 = 136 years for the other 4 members, so their average is 136 / 4 = 34 years. (35 = 140 / 4 forgets to subtract the child's age first.)"},
  {"id":"SP-W4-Q6","week":4,"category":"Statistics and Probability","topic":"mode, median and mean combined","difficulty":"H","estSecs":100,"question":"A list of five positive whole numbers has a mode of 4 (which appears exactly twice), a median of 5 and a mean of 6. No value other than 4 is repeated. What is the largest possible number in the list?","options":{"A":"9","B":"10","C":"11","D":"12","E":"13"},"answer":"C","explanation":"The mean is 6, so the five numbers total 5 x 6 = 30. The two 4s are the only repeated value and 4 is less than the median 5, so they must be the two smallest: 4, 4, then the median 5, then two larger numbers. So far 4 + 4 + 5 = 13, leaving 17 for the last two, which must both be greater than 5 and different. To make one as large as possible, make the other as small as possible: 6, giving 17 - 6 = 11. Check: 4, 4, 5, 6, 11 has total 30, median 5, and 4 as the only repeat. The largest is 11."},
  {"id":"SP-W4-Q7","week":4,"category":"Statistics and Probability","topic":"combined events","difficulty":"H","estSecs":100,"question":"Spinner P has 4 equal sections numbered 1, 2, 3, 4. Spinner Q has 3 equal sections numbered 2, 4, 6. Both spinners are spun once and the two numbers are multiplied. What is the probability that the product is greater than 10?","options":{"A":"1/3","B":"2/3","C":"1/2","D":"7/12","E":"5/12"},"answer":"E","explanation":"There are 4 x 3 = 12 equally likely outcomes. Products greater than 10: with P = 2, only 2 x 6 = 12 (1 outcome); with P = 3, 3 x 4 = 12 and 3 x 6 = 18 (2 outcomes); with P = 4, 4 x 4 = 16 and 4 x 6 = 24 (2 outcomes); P = 1 gives none. That is 1 + 2 + 2 = 5 outcomes, so the probability is 5/12."},
  {"id":"PS-W1-Q1","week":1,"category":"Problem Solving","topic":"venn 3 sets","difficulty":"H","estSecs":100,"question":"In a class of 30 students, every student plays at least one of three sports: soccer, tennis or cricket. 18 students play soccer, 15 play tennis and 14 play cricket. 8 play both soccer and tennis, 7 play both soccer and cricket, and 6 play both tennis and cricket. How many students play all three sports? (Each 'both' count includes those who play all three.)","options":{"A":"3","B":"4","C":"5","D":"6","E":"8"},"answer":"B","explanation":"Use the inclusion-exclusion rule. Total in at least one set = (sum of singles) - (sum of pairs) + (all three). So 30 = (18 + 15 + 14) - (8 + 7 + 6) + x = 47 - 21 + x = 26 + x. Therefore x = 30 - 26 = 4 students play all three sports."},
  {"id":"PS-W1-Q2","week":1,"category":"Problem Solving","topic":"working backwards","difficulty":"M","estSecs":70,"question":"Tom thinks of a whole number. He multiplies it by 3, then adds 7, then divides the result by 2, and finally subtracts 4. His answer is 10. What number did Tom start with?","options":{"A":"6","B":"7","C":"5","D":"8","E":"9"},"answer":"B","explanation":"Work backwards, reversing each operation. Start from 10. Undo 'subtract 4' by adding 4: 10 + 4 = 14. Undo 'divide by 2' by multiplying by 2: 14 x 2 = 28. Undo 'add 7' by subtracting 7: 28 - 7 = 21. Undo 'multiply by 3' by dividing by 3: 21 / 3 = 7. The starting number is 7. Check: 7 x 3 = 21, + 7 = 28, / 2 = 14, - 4 = 10."},
  {"id":"PS-W1-Q3","week":1,"category":"Problem Solving","topic":"age problem","difficulty":"M","estSecs":70,"question":"A mother is currently 4 times as old as her daughter. In 5 years' time, the mother will be 3 times as old as her daughter. How old is the daughter now?","options":{"A":"8","B":"12","C":"9","D":"10","E":"15"},"answer":"D","explanation":"Let the daughter be d years old now, so the mother is 4d. In 5 years the daughter is d + 5 and the mother is 4d + 5. The condition gives 4d + 5 = 3(d + 5) = 3d + 15. So 4d - 3d = 15 - 5, giving d = 10. The daughter is 10 (mother 40). Check in 5 years: 45 = 3 x 15. Correct."},
  {"id":"PS-W1-Q4","week":1,"category":"Problem Solving","topic":"coin/money combinations","difficulty":"M","estSecs":70,"question":"Sarah has exactly 20 coins, made up only of 10-cent and 20-cent coins. Altogether they are worth $3.10. How many 20-cent coins does she have?","options":{"A":"9","B":"10","C":"12","D":"13","E":"11"},"answer":"E","explanation":"Let x be the number of 20c coins and y the number of 10c coins. Then x + y = 20 and 20x + 10y = 310. Divide the money equation by 10: 2x + y = 31. Subtract the first equation: (2x + y) - (x + y) = 31 - 20, giving x = 11. So there are 11 twenty-cent coins (and 9 ten-cent coins). Check: 11 x 20 + 9 x 10 = 220 + 90 = 310 cents = $3.10."},
  {"id":"PS-W1-Q5","week":1,"category":"Problem Solving","topic":"distance-rate-time","difficulty":"M","estSecs":70,"question":"A cyclist rides 36 km to a lake at a steady 12 km/h, rests for 30 minutes at the lake, then returns along the same road at 18 km/h. How long does the whole trip take, including the rest?","options":{"A":"5 hours","B":"6 hours 30 minutes","C":"5 hours 15 minutes","D":"6 hours","E":"5 hours 30 minutes"},"answer":"E","explanation":"Time out = distance / speed = 36 / 12 = 3 hours. Rest = 30 minutes = 0.5 hour. Time back = 36 / 18 = 2 hours. Total = 3 + 0.5 + 2 = 5.5 hours = 5 hours 30 minutes."},
  {"id":"PS-W1-Q6","week":1,"category":"Problem Solving","topic":"systematic listing/counting","difficulty":"M","estSecs":70,"question":"Using the digits 1, 2, 3 and 4, with no digit repeated in a number, how many different 3-digit even numbers can be formed?","options":{"A":"16","B":"10","C":"8","D":"12","E":"24"},"answer":"D","explanation":"For an even number the last digit must be 2 or 4, giving 2 choices. Once the last digit is chosen, 3 digits remain: the first digit has 3 choices and the middle digit has 2 choices, so 3 x 2 = 6 ways for the first two places. Total = 2 x 6 = 12 even numbers. (The value 24 is the count of all 3-digit numbers with no repeat, not just the even ones.)"},
  {"id":"PS-W1-Q7","week":1,"category":"Problem Solving","topic":"pattern recognition sequences","difficulty":"M","estSecs":70,"question":"A sequence begins 2, 6, 12, 20, 30, ... where the gaps are 4, 6, 8, 10, ... What is the 8th term of the sequence?","options":{"A":"56","B":"80","C":"64","D":"72","E":"90"},"answer":"D","explanation":"The gaps are 4, 6, 8, 10, 12, 14, ... Continue: 30 (5th), +12 = 42 (6th), +14 = 56 (7th), +16 = 72 (8th). Alternatively each term is n x (n + 1): 1x2=2, 2x3=6, ..., 8x9=72. The 8th term is 72. (56 is only the 7th term.)"},
  {"id":"PS-W2-Q1","week":2,"category":"Problem Solving","topic":"venn 2 sets","difficulty":"M","estSecs":70,"question":"In a group of 40 people, 25 like coffee and 20 like tea. 8 people like neither drink. How many people like both coffee and tea?","options":{"A":"18","B":"13","C":"5","D":"8","E":"15"},"answer":"B","explanation":"People who like at least one drink = 40 - 8 (neither) = 32. By the two-set rule, (coffee) + (tea) - (both) = at least one. So 25 + 20 - both = 32, giving 45 - both = 32, so both = 13. Check: coffee only 12, tea only 7, both 13, neither 8 -> 12 + 7 + 13 + 8 = 40."},
  {"id":"PS-W2-Q2","week":2,"category":"Problem Solving","topic":"logic deduction","difficulty":"M","estSecs":70,"question":"Amy, Ben, Cara and Dan ran a race with no ties. Amy finished ahead of Ben. Cara finished after Ben. Dan finished ahead of Amy. Who finished last?","options":{"A":"Amy","B":"Ben","C":"Cara","D":"Dan","E":"Cannot be determined"},"answer":"C","explanation":"From 'Dan ahead of Amy' and 'Amy ahead of Ben' we get Dan, then Amy, then Ben. 'Cara after Ben' puts Cara behind Ben. So the full finishing order is Dan, Amy, Ben, Cara. Cara finished last."},
  {"id":"PS-W2-Q3","week":2,"category":"Problem Solving","topic":"working backwards","difficulty":"M","estSecs":70,"question":"Sam spent half of his money on a game, then spent another $12 on lunch. He has $18 left. How much money did Sam start with?","options":{"A":"$60","B":"$36","C":"$54","D":"$72","E":"$48"},"answer":"A","explanation":"Work backwards from $18. Before lunch he had 18 + 12 = $30. That $30 is what remained after spending half, so it is the other half of his money. His starting amount is 30 x 2 = $60. Check: half of 60 is 30 spent on the game (30 left), then 12 on lunch leaves 18."},
  {"id":"PS-W2-Q4","week":2,"category":"Problem Solving","topic":"age problem","difficulty":"M","estSecs":70,"question":"The ages of two sisters add up to 28 years. In 4 years' time, the older sister will be exactly twice as old as the younger sister. How old is the younger sister now?","options":{"A":"8","B":"7","C":"6","D":"10","E":"12"},"answer":"A","explanation":"Let the younger sister be y, so the older is 28 - y. In 4 years they are y + 4 and 28 - y + 4 = 32 - y. The condition: 32 - y = 2(y + 4) = 2y + 8. So 32 - 8 = 3y, giving 24 = 3y, y = 8. The younger sister is 8 (older 20). Check in 4 years: 24 = 2 x 12. Correct."},
  {"id":"PS-W2-Q5","week":2,"category":"Problem Solving","topic":"coin/money combinations","difficulty":"M","estSecs":70,"question":"A money box contains only $2 coins and 50-cent coins. There are 30 coins in total, worth $39 altogether. How many $2 coins are in the box?","options":{"A":"18","B":"16","C":"12","D":"14","E":"20"},"answer":"B","explanation":"Let x be the number of $2 coins and y the number of 50c coins. Then x + y = 30 and 2x + 0.5y = 39. Multiply the money equation by 2: 4x + y = 78. Subtract the first equation: (4x + y) - (x + y) = 78 - 30, giving 3x = 48, so x = 16. There are 16 two-dollar coins (and 14 fifty-cent coins). Check: 16 x 2 + 14 x 0.5 = 32 + 7 = $39."},
  {"id":"PS-W2-Q6","week":2,"category":"Problem Solving","topic":"distance-rate-time","difficulty":"H","estSecs":100,"question":"Two trains start 300 km apart on the same track and travel directly towards each other. One travels at 60 km/h and the other at 40 km/h. How far has the faster train travelled at the moment they meet?","options":{"A":"120 km","B":"150 km","C":"240 km","D":"180 km","E":"200 km"},"answer":"D","explanation":"The gap closes at the combined speed 60 + 40 = 100 km/h. Time to meet = 300 / 100 = 3 hours. In 3 hours the faster train travels 60 x 3 = 180 km. (Check: the slower travels 40 x 3 = 120 km, and 180 + 120 = 300 km.)"},
  {"id":"PS-W2-Q7","week":2,"category":"Problem Solving","topic":"systematic counting","difficulty":"M","estSecs":70,"question":"At a party, every one of the 6 guests shakes hands exactly once with every other guest. How many handshakes take place in total?","options":{"A":"12","B":"15","C":"18","D":"21","E":"30"},"answer":"B","explanation":"Each of the 6 people shakes hands with the other 5, giving 6 x 5 = 30, but this counts every handshake twice (once for each person). So the number of handshakes = 30 / 2 = 15. (The value 30 is the common mistake of forgetting to halve.)"},
  {"id":"PS-W3-Q1","week":3,"category":"Problem Solving","topic":"venn 3 sets","difficulty":"H","estSecs":100,"question":"50 students were surveyed about which fruits they like: 30 like apples, 25 like bananas and 20 like cherries. 12 like both apples and bananas, 10 like both bananas and cherries, 9 like both apples and cherries, and 5 like all three fruits. How many students like none of these fruits? (Each pair count includes the 5 who like all three.)","options":{"A":"5","B":"0","C":"3","D":"6","E":"1"},"answer":"E","explanation":"By inclusion-exclusion, the number liking at least one fruit = 30 + 25 + 20 - 12 - 10 - 9 + 5 = 75 - 31 + 5 = 49. Students liking none = total - at least one = 50 - 49 = 1."},
  {"id":"PS-W3-Q2","week":3,"category":"Problem Solving","topic":"logic deduction","difficulty":"M","estSecs":70,"question":"Three boxes are labelled 'Apples', 'Oranges' and 'Mixed'. Each box holds only apples, only oranges, or a mix, but every single label is wrong. You take one fruit from the box labelled 'Mixed' and it is an apple. What does that box actually contain?","options":{"A":"Only oranges","B":"Equal apples and oranges","C":"A mix of apples and oranges","D":"Cannot be determined","E":"Only apples"},"answer":"E","explanation":"Because every label is wrong, the box labelled 'Mixed' is definitely NOT the mixed box; it must be a pure box (only apples or only oranges). Since the fruit you drew is an apple, the box cannot be the oranges-only box, so it must contain only apples."},
  {"id":"PS-W3-Q3","week":3,"category":"Problem Solving","topic":"working backwards","difficulty":"H","estSecs":100,"question":"A frog is climbing out of a well that is 10 metres deep. Each day it climbs up 3 metres, but each night it slips back down 2 metres. It starts at the bottom. On which day does the frog first reach the top and get out?","options":{"A":"Day 8","B":"Day 7","C":"Day 9","D":"Day 10","E":"Day 11"},"answer":"A","explanation":"Each full day-and-night the frog gains a net 1 metre, but on the day it reaches the top it climbs out before slipping. At the start of each day the frog is 1 m higher than the day before. At the start of day 8 it is at 7 m; it then climbs 3 m to reach 10 m and gets out. Check: it never reaches 10 m earlier, since at the start of day 7 it is only at 6 m and climbs to 9 m."},
  {"id":"PS-W3-Q4","week":3,"category":"Problem Solving","topic":"age problem","difficulty":"M","estSecs":70,"question":"A father's age is 3 more than 4 times his son's age. In 6 years' time, the father will be exactly 3 times as old as his son. How old is the son now?","options":{"A":"11","B":"9","C":"8","D":"10","E":"7"},"answer":"B","explanation":"Let the son be s. The father is 4s + 3. In 6 years: son is s + 6, father is 4s + 3 + 6 = 4s + 9. The condition: 4s + 9 = 3(s + 6) = 3s + 18. So 4s - 3s = 18 - 9, giving s = 9. The son is 9 (father 39). Check in 6 years: 45 = 3 x 15. Correct."},
  {"id":"PS-W3-Q5","week":3,"category":"Problem Solving","topic":"coin/money combinations","difficulty":"M","estSecs":70,"question":"Ben has a collection of 5-cent, 10-cent and 20-cent coins worth $4.60 in total. He has twice as many 10-cent coins as 5-cent coins, and 3 fewer 20-cent coins than 10-cent coins. How many 20-cent coins does he have?","options":{"A":"8","B":"16","C":"10","D":"11","E":"13"},"answer":"E","explanation":"Let the number of 5c coins be a. Then 10c coins = 2a and 20c coins = 2a - 3. Total value in cents: 5(a) + 10(2a) + 20(2a - 3) = 460. This is 5a + 20a + 40a - 60 = 65a - 60 = 460, so 65a = 520 and a = 8. Then 10c coins = 16 and 20c coins = 2(8) - 3 = 13. Check: 5x8 + 10x16 + 20x13 = 40 + 160 + 260 = 460 cents = $4.60."},
  {"id":"PS-W3-Q6","week":3,"category":"Problem Solving","topic":"distance-rate-time","difficulty":"H","estSecs":100,"question":"A car drives the first 100 km of a trip at 50 km/h, then drives the next 100 km at 100 km/h. What is the car's average speed for the whole 200 km trip?","options":{"A":"70 km/h","B":"75 km/h","C":"66 and 2/3 km/h","D":"60 km/h","E":"80 km/h"},"answer":"C","explanation":"Average speed = total distance / total time, not the average of the two speeds. Time for first part = 100 / 50 = 2 hours; time for second part = 100 / 100 = 1 hour. Total distance 200 km in 3 hours, so average speed = 200 / 3 = 66 and 2/3 km/h. (75 km/h is the trap answer from just averaging 50 and 100.)"},
  {"id":"PS-W3-Q7","week":3,"category":"Problem Solving","topic":"systematic counting","difficulty":"H","estSecs":100,"question":"A grid is made of 3 rows and 3 columns of small unit squares (a 3 by 3 board). How many squares of ALL sizes can be found in the grid altogether?","options":{"A":"9","B":"10","C":"14","D":"15","E":"13"},"answer":"C","explanation":"Count squares by size. 1x1 squares: 3 x 3 = 9. 2x2 squares: their top-left corner can be in a 2 x 2 arrangement, so 2 x 2 = 4. 3x3 squares: just 1. Total = 9 + 4 + 1 = 14. (The answer 9 is the common mistake of counting only the smallest squares.)"},
  {"id":"PS-W4-Q1","week":4,"category":"Problem Solving","topic":"venn 2 sets","difficulty":"M","estSecs":70,"question":"In a class, 22 students play a musical instrument and 18 play a sport. 5 students do both, and 3 students do neither. How many students are in the class altogether?","options":{"A":"33","B":"35","C":"38","D":"40","E":"43"},"answer":"C","explanation":"Students who play at least one activity = (instrument) + (sport) - (both) = 22 + 18 - 5 = 35. Add the 3 who do neither: 35 + 3 = 38 students in the class. (35 is the trap answer from forgetting the 'neither' group; 40 comes from also forgetting to subtract the overlap.)"},
  {"id":"PS-W4-Q2","week":4,"category":"Problem Solving","topic":"logic deduction","difficulty":"M","estSecs":70,"question":"Five students sat a test with no equal scores. Priya scored higher than Quinn. Rohan scored lower than Quinn. Sam scored higher than Priya but lower than Tara, who scored the highest of all five. Who came 4th (second lowest)?","options":{"A":"Tara","B":"Rohan","C":"Priya","D":"Sam","E":"Quinn"},"answer":"E","explanation":"Tara is highest. Sam is below Tara but above Priya, so Tara > Sam > Priya. Priya > Quinn > Rohan. Combining: Tara (1st) > Sam (2nd) > Priya (3rd) > Quinn (4th) > Rohan (5th). The 4th place is Quinn."},
  {"id":"PS-W4-Q3","week":4,"category":"Problem Solving","topic":"working backwards","difficulty":"H","estSecs":100,"question":"A shopkeeper sells apples. To the first customer she sells half of all her apples plus 1 more. To the second customer she sells half of what remained plus 1 more. She then has 8 apples left. How many apples did she start with?","options":{"A":"30","B":"38","C":"34","D":"40","E":"46"},"answer":"B","explanation":"Work backwards. After the second sale she has 8. Before the second sale: half minus 1 equals 8, so half of that amount was 8 + 1 = 9, meaning she had 9 x 2 = 18. Before the first sale: similarly 18 + 1 = 19 was half, so she had 19 x 2 = 38. Check: 38 -> sell 19 + 1 = 20, leaves 18 -> sell 9 + 1 = 10, leaves 8. Started with 38."},
  {"id":"PS-W4-Q4","week":4,"category":"Problem Solving","topic":"age problem","difficulty":"M","estSecs":70,"question":"Anna is currently 3 times as old as Ben. Five years ago, Anna was 5 times as old as Ben was then. How old is Anna now?","options":{"A":"30","B":"24","C":"36","D":"15","E":"45"},"answer":"A","explanation":"Let Ben be b now, so Anna is 3b. Five years ago Anna was 3b - 5 and Ben was b - 5. The condition: 3b - 5 = 5(b - 5) = 5b - 25. So 25 - 5 = 5b - 3b, giving 20 = 2b, b = 10. Anna is 3 x 10 = 30. Check five years ago: 25 = 5 x 5. Correct."},
  {"id":"PS-W4-Q5","week":4,"category":"Problem Solving","topic":"coin/money combinations","difficulty":"M","estSecs":70,"question":"Using only 10-cent coins and 20-cent coins (and at least one coin), in how many different ways can you make exactly 50 cents? (The number of each type of coin can be anything, including zero of one type.)","options":{"A":"2","B":"6","C":"3","D":"5","E":"4"},"answer":"C","explanation":"List by the number of 20c coins. Zero 20c: need 50c from 10c coins = five 10c coins. One 20c: 30c left = three 10c coins. Two 20c: 10c left = one 10c coin. Three 20c would be 60c, too much. So the ways are: (5 ten-cent), (3 ten-cent + 1 twenty-cent), (1 ten-cent + 2 twenty-cent) = 3 different ways."},
  {"id":"PS-W4-Q6","week":4,"category":"Problem Solving","topic":"distance-rate-time","difficulty":"H","estSecs":100,"question":"Anna leaves home at 8:00 am walking along a straight road at 5 km/h. At 9:00 am, Ben leaves the same spot cycling along the same road in the same direction at 15 km/h. At what time does Ben catch up to Anna?","options":{"A":"9:30 am","B":"9:15 am","C":"9:45 am","D":"10:00 am","E":"10:30 am"},"answer":"A","explanation":"By 9:00 am Anna has walked for 1 hour at 5 km/h, so she is 5 km ahead. Ben gains on her at 15 - 5 = 10 km/h. Time to close the 5 km gap = 5 / 10 = 0.5 hour = 30 minutes. So Ben catches Anna at 9:00 am + 30 min = 9:30 am."},
  {"id":"PS-W4-Q7","week":4,"category":"Problem Solving","topic":"pattern recognition sequences","difficulty":"M","estSecs":70,"question":"A growing dot pattern has 1 dot in Figure 1, 5 dots in Figure 2, 13 dots in Figure 3 and 25 dots in Figure 4. If the pattern continues in the same way, how many dots are in Figure 5?","options":{"A":"41","B":"37","C":"39","D":"45","E":"61"},"answer":"A","explanation":"Look at the differences between figures: 5 - 1 = 4, 13 - 5 = 8, 25 - 13 = 12. The differences go up by 4 each time (4, 8, 12, ...), so the next difference is 16. Figure 5 = 25 + 16 = 41 dots."},
  {"id":"DI-W1-Q1","week":1,"category":"Data Interpretation","topic":"two-way table","difficulty":"E","estSecs":45,"question":"A survey of 120 students recorded their pet ownership by year group.\n\n              Dog   Cat   None   Total\nYear 5:        22    15    18      55\nYear 6:        30    20    15      65\nTotal:         52    35    33     120\n\nOf all the students who own a cat, what fraction are in Year 6?","options":{"A":"1/6","B":"4/7","C":"3/7","D":"4/13","E":"4/11"},"answer":"B","explanation":"Total cat owners = 15 + 20 = 35. Year 6 cat owners = 20. The fraction is 20/35. Dividing top and bottom by 5 gives 4/7. (4/13 wrongly uses the Year 6 total 65; 3/7 = 15/35 is the Year 5 share; 1/6 = 20/120 uses the whole survey.)"},
  {"id":"DI-W1-Q2","week":1,"category":"Data Interpretation","topic":"table of values","difficulty":"E","estSecs":45,"question":"A weather station recorded rainfall (in mm) for one week:\nMon: 12, Tue: 18, Wed: 9, Thu: 24, Fri: 15, Sat: 28, Sun: 6.\n\nOn how many days was the rainfall GREATER than the mean daily rainfall for the week?","options":{"A":"2","B":"3","C":"4","D":"5","E":"1"},"answer":"B","explanation":"Total rainfall = 12 + 18 + 9 + 24 + 15 + 28 + 6 = 112 mm. Mean = 112 / 7 = 16 mm. Days above 16 mm: Tue (18), Thu (24), Sat (28) = 3 days. (Counting days of 15 mm or more gives the wrong answer of 4.)"},
  {"id":"DI-W1-Q3","week":1,"category":"Data Interpretation","topic":"line/trend data","difficulty":"M","estSecs":70,"question":"A weather station logged the temperature each hour (in degrees C):\n9am: 14, 10am: 18, 11am: 19, 12pm: 22, 1pm: 22, 2pm: 20, 3pm: 16.\n\nDuring which one-hour interval did the temperature RISE the most?","options":{"A":"11am-12pm","B":"9am-10am","C":"10am-11am","D":"12pm-1pm","E":"2pm-3pm"},"answer":"B","explanation":"Hour-by-hour changes: 9-10am +4, 10-11am +1, 11am-12pm +3, 12-1pm 0, 1-2pm -2, 2-3pm -4. The largest rise is +4 during 9am-10am. (2pm-3pm is the largest FALL, -4, a common trap.)"},
  {"id":"DI-W1-Q4","week":1,"category":"Data Interpretation","topic":"price list / menu","difficulty":"M","estSecs":70,"question":"A cafe menu lists: Sandwich $6.50, Wrap $7.20, Juice $3.80, Muffin $2.90, Coffee $4.10.\n\nA family buys 2 sandwiches, 1 wrap, 3 juices and 2 muffins, and pays with a $50 note. How much change do they receive?","options":{"A":"$37.40","B":"$16.40","C":"$9.80","D":"$12.40","E":"$12.60"},"answer":"E","explanation":"2 sandwiches = 2 x $6.50 = $13.00; 1 wrap = $7.20; 3 juices = 3 x $3.80 = $11.40; 2 muffins = 2 x $2.90 = $5.80. Total = 13.00 + 7.20 + 11.40 + 5.80 = $37.40. Change = $50.00 - $37.40 = $12.60. ($16.40 comes from buying only 2 juices; $37.40 is the total, not the change.)"},
  {"id":"DI-W1-Q5","week":1,"category":"Data Interpretation","topic":"timetable","difficulty":"M","estSecs":70,"question":"Three buses travel from Central to Pier, stopping at Museum on the way:\nBus A: Central 7:40, Museum 8:05, Pier 8:35\nBus B: Central 8:10, Museum 8:33, Pier 9:00\nBus C: Central 8:50, Museum 9:10, Pier 9:38\n\nWhich bus completes the whole Central-to-Pier trip in the SHORTEST time?","options":{"A":"Bus A","B":"Bus B","C":"Bus C","D":"All take the same time","E":"Bus A and Bus B (tied)"},"answer":"C","explanation":"Trip times: Bus A 7:40 to 8:35 = 55 min; Bus B 8:10 to 9:00 = 50 min; Bus C 8:50 to 9:38 = 48 min. Bus C is quickest at 48 minutes. (Leaving earliest, Bus A, does not mean shortest journey.)"},
  {"id":"DI-W1-Q6","week":1,"category":"Data Interpretation","topic":"bar/column data","difficulty":"E","estSecs":45,"question":"An ice-cream shop recorded cones sold by flavour:\nVanilla: 48, Chocolate: 60, Strawberry: 36, Mango: 54, Mint: 42.\n\nChocolate sales were what percentage of the total number of cones sold?","options":{"A":"24%","B":"20%","C":"30%","D":"25%","E":"15%"},"answer":"D","explanation":"Total cones = 48 + 60 + 36 + 54 + 42 = 240. Chocolate = 60. 60/240 = 1/4 = 25%. (20% would be 48/240; 60/240 is exactly one quarter.)"},
  {"id":"DI-W1-Q7","week":1,"category":"Data Interpretation","topic":"what-if inference","difficulty":"M","estSecs":70,"question":"Five students scored (out of 10): Amy 7, Ben 9, Cara 6, Dan 8, Eve 5. A sixth student, Finn, will be added. What score must Finn get so the mean score of all 6 students is exactly 7?","options":{"A":"7","B":"8","C":"6","D":"9","E":"42"},"answer":"A","explanation":"Current total = 7 + 9 + 6 + 8 + 5 = 35. For a mean of 7 over 6 students the total must be 6 x 7 = 42. Finn's score = 42 - 35 = 7. (42 is the required total, not Finn's individual score.)"},
  {"id":"DI-W2-Q1","week":2,"category":"Data Interpretation","topic":"two-way table","difficulty":"E","estSecs":45,"question":"100 students chose a favourite film type:\n              Action  Comedy  Drama  Total\nBoys:           24      18      8      50\nGirls:          16      22     12      50\nTotal:          40      40     20     100\n\nOf all the students who prefer Action, what fraction are girls?","options":{"A":"4/25","B":"8/25","C":"2/5","D":"3/5","E":"2/3"},"answer":"C","explanation":"Action total = 24 + 16 = 40. Girls choosing Action = 16. Fraction = 16/40 = 2/5. (3/5 = 24/40 is the boys' share; 4/25 = 16/100 uses the whole group.)"},
  {"id":"DI-W2-Q2","week":2,"category":"Data Interpretation","topic":"table of values","difficulty":"E","estSecs":45,"question":"A fruit stall sells (price per kg): Apples $4, Bananas $3, Cherries $12, Grapes $8.\nOn Saturday it sold: Apples 15 kg, Bananas 20 kg, Cherries 5 kg, Grapes 9 kg.\n\nWhich fruit earned the MOST money on Saturday?","options":{"A":"Bananas","B":"Cherries","C":"Apples","D":"Grapes","E":"They all earned the same"},"answer":"D","explanation":"Earnings: Apples 15 x $4 = $60; Bananas 20 x $3 = $60; Cherries 5 x $12 = $60; Grapes 9 x $8 = $72. Grapes earned the most at $72. (The other three all tie at $60, which is the trap.)"},
  {"id":"DI-W2-Q3","week":2,"category":"Data Interpretation","topic":"line/trend data","difficulty":"M","estSecs":70,"question":"Daily visitors to a website were:\nMon 340, Tue 380, Wed 360, Thu 420, Fri 500, Sat 620, Sun 580.\n\nOn which day did the number of visitors INCREASE the most compared with the previous day?","options":{"A":"Tuesday","B":"Friday","C":"Saturday","D":"Sunday","E":"Thursday"},"answer":"C","explanation":"Day-on-day changes: Tue +40, Wed -20, Thu +60, Fri +80, Sat +120, Sun -40. The biggest increase is +120 on Saturday. (Friday's +80 is the second largest; Sunday actually fell by 40.)"},
  {"id":"DI-W2-Q4","week":2,"category":"Data Interpretation","topic":"price list / menu","difficulty":"M","estSecs":70,"question":"A pizza shop charges: Small $9, Medium $13, Large $17, each topping $1.50, garlic bread $5.\n\nAn order is: 2 Large pizzas each with 3 toppings, 1 Medium pizza with 2 toppings, and 2 garlic breads. What is the total cost?","options":{"A":"$67.50","B":"$64.00","C":"$70.50","D":"$69.00","E":"$59.00"},"answer":"D","explanation":"2 Large = 2 x $17 = $34; their toppings = 2 x 3 x $1.50 = $9.00. 1 Medium = $13; its toppings = 2 x $1.50 = $3.00. Garlic bread = 2 x $5 = $10. Total = 34 + 9 + 13 + 3 + 10 = $69.00. ($59.00 forgets the toppings on one pizza.)"},
  {"id":"DI-W2-Q5","week":2,"category":"Data Interpretation","topic":"timetable","difficulty":"M","estSecs":70,"question":"Trains leave Station X every 25 minutes, with the first at 6:15am. Each trip to Station Y takes 40 minutes.\n\nMeera must ARRIVE at Station Y by 9:00am. What is the latest train she can catch from Station X?","options":{"A":"8:00am","B":"8:45am","C":"7:55am","D":"8:35am","E":"8:20am"},"answer":"E","explanation":"Departures: 6:15, 6:40, 7:05, 7:30, 7:55, 8:20, 8:45, ... Add 40 minutes for arrival. 8:20 + 40 = 9:00 (arrives just in time). 8:45 + 40 = 9:25 (too late). So the latest suitable train departs at 8:20am. (8:45 arrives after 9:00.)"},
  {"id":"DI-W2-Q6","week":2,"category":"Data Interpretation","topic":"bar data with missing category","difficulty":"M","estSecs":70,"question":"Five players' goals were: Ali 12, Bo 9, Cy 15, Di 6, Ed 18. The whole team scored 75 goals in total.\n\nWhat fraction of the team's goals were scored by players OTHER than these five?","options":{"A":"12/75","B":"4/5","C":"1/6","D":"1/5","E":"1/4"},"answer":"D","explanation":"Listed goals = 12 + 9 + 15 + 6 + 18 = 60. Others = 75 - 60 = 15. Fraction = 15/75 = 1/5. (4/5 is the share the five players scored; 1/4 = 15/60 wrongly uses 60 as the total.)"},
  {"id":"DI-W2-Q7","week":2,"category":"Data Interpretation","topic":"what-if inference","difficulty":"E","estSecs":45,"question":"A bakery's daily bread sales were: Mon 40, Tue 55, Wed 48, Thu 62, Fri ?\nThe mean over the five days was 52 loaves. How many loaves were sold on Friday?","options":{"A":"45","B":"52","C":"50","D":"65","E":"55"},"answer":"E","explanation":"For a mean of 52 over 5 days the total must be 5 x 52 = 260. Known days: 40 + 55 + 48 + 62 = 205. Friday = 260 - 205 = 55. (52 mistakes the mean for the missing value.)"},
  {"id":"DI-W3-Q1","week":3,"category":"Data Interpretation","topic":"two-way table","difficulty":"E","estSecs":45,"question":"How 180 students travel to school:\n              Walk  Bus  Car  Total\nYear 4:        20    30   10    60\nYear 5:        15    25   20    60\nYear 6:        25    20   15    60\nTotal:         60    75   45   180\n\nWhich mode of transport is used by exactly one-third of all the students?","options":{"A":"Walk","B":"Bus","C":"Car","D":"Walk and Car together","E":"None of them"},"answer":"A","explanation":"One-third of 180 = 60. Column totals: Walk = 20 + 15 + 25 = 60; Bus = 30 + 25 + 20 = 75; Car = 10 + 20 + 15 = 45. Only Walk equals 60, so Walk is used by exactly one-third."},
  {"id":"DI-W3-Q2","week":3,"category":"Data Interpretation","topic":"recipe scaling","difficulty":"E","estSecs":45,"question":"A recipe that serves 4 people uses:\nFlour 200 g, Sugar 150 g, Butter 120 g, Eggs 2.\n\nPriya makes the recipe for 10 people. How much sugar does she need?","options":{"A":"375 g","B":"300 g","C":"350 g","D":"450 g","E":"187.5 g"},"answer":"A","explanation":"Sugar per person = 150 / 4 = 37.5 g. For 10 people = 37.5 x 10 = 375 g. (300 g would serve 8 people, i.e. doubling; 450 g would serve 12.)"},
  {"id":"DI-W3-Q3","week":3,"category":"Data Interpretation","topic":"line/trend data","difficulty":"M","estSecs":70,"question":"A plant's height (in cm) was measured weekly:\nWeek 0: 5, Week 1: 8, Week 2: 13, Week 3: 20, Week 4: 26.\n\nIn which week did the plant's height INCREASE the most compared with the week before?","options":{"A":"Week 2 and Week 3 (tied)","B":"Week 4","C":"Week 2","D":"Week 3","E":"Week 1"},"answer":"D","explanation":"Weekly increases: Week 1 +3, Week 2 +5, Week 3 +7, Week 4 +6. The largest increase is +7 in Week 3 (from 13 cm to 20 cm). (Week 4 has the tallest plant but only grew +6.)"},
  {"id":"DI-W3-Q4","week":3,"category":"Data Interpretation","topic":"deal comparison","difficulty":"H","estSecs":100,"question":"Cinema prices: Adult $19, Child $13. A Family Pass (2 adults + 2 children) costs $58. A Combo (popcorn + drink) costs $11, but popcorn ($8) and drink ($6) can also be bought separately.\n\nA group of 2 adults and 2 children want tickets plus 4 combos. What is the LOWEST possible total cost?","options":{"A":"$114","B":"$108","C":"$120","D":"$102","E":"$98"},"answer":"D","explanation":"Tickets: Family Pass = $58, which is cheaper than buying separately (2 x $19 + 2 x $13 = $64). Combos: 4 x $11 = $44 (cheaper than 4 x ($8 + $6) = $56). Lowest total = $58 + $44 = $102. (Separate tickets + combos = $108; buying snacks separately pushes it higher.)"},
  {"id":"DI-W3-Q5","week":3,"category":"Data Interpretation","topic":"timetable","difficulty":"M","estSecs":70,"question":"A ferry leaves Wharf A at 10:20, arrives Wharf B at 10:50, waits 8 minutes, then travels on and arrives Wharf C at 11:35.\n\nHow many minutes was the ferry actually MOVING (excluding the wait)?","options":{"A":"67 minutes","B":"75 minutes","C":"65 minutes","D":"60 minutes","E":"1 hour 15 minutes"},"answer":"A","explanation":"A to B: 10:20 to 10:50 = 30 min. It waits 8 min, so leaves B at 10:58. B to C: 10:58 to 11:35 = 37 min. Moving time = 30 + 37 = 67 min. (75 min, or 1 h 15 min, is the total elapsed time including the 8-minute wait.)"},
  {"id":"DI-W3-Q6","week":3,"category":"Data Interpretation","topic":"two-group comparison","difficulty":"E","estSecs":45,"question":"Recycling collected (in kg):\nClass 6A - Paper 24, Plastic 18, Glass 15.\nClass 6B - Paper 20, Plastic 27, Glass 12.\n\nHow much more total recycling did the class with the larger total collect, compared with the other class?","options":{"A":"1 kg","B":"3 kg","C":"2 kg","D":"9 kg","E":"5 kg"},"answer":"C","explanation":"6A total = 24 + 18 + 15 = 57 kg. 6B total = 20 + 27 + 12 = 59 kg. 6B is larger. Difference = 59 - 57 = 2 kg. (9 kg is the plastic difference alone; 4 kg is the paper difference - neither is the total difference.)"},
  {"id":"DI-W3-Q7","week":3,"category":"Data Interpretation","topic":"what-if inference","difficulty":"H","estSecs":100,"question":"The scores in 4 games were: 15, 22, 18, 25. A fifth game is played. After 5 games the mean score is exactly 1 more than the mean of the first 4 games. What was the fifth game's score?","options":{"A":"25","B":"21","C":"20","D":"26","E":"30"},"answer":"A","explanation":"Mean of first 4 = (15 + 22 + 18 + 25) / 4 = 80 / 4 = 20. New mean = 21, so total over 5 games = 5 x 21 = 105. Fifth score = 105 - 80 = 25. (21 is the new mean, not the fifth score.)"},
  {"id":"DI-W4-Q1","week":4,"category":"Data Interpretation","topic":"two-way table","difficulty":"E","estSecs":45,"question":"Tickets sold at a show:\n              Standard  VIP\nFriday:         120      30\nSaturday:       200      50\n\nA Standard ticket costs $25 and a VIP ticket costs $60. How much MORE revenue was taken on Saturday than on Friday?","options":{"A":"$3200","B":"$3000","C":"$2000","D":"$3600","E":"$8000"},"answer":"A","explanation":"Friday revenue = 120 x $25 + 30 x $60 = $3000 + $1800 = $4800. Saturday revenue = 200 x $25 + 50 x $60 = $5000 + $3000 = $8000. Difference = $8000 - $4800 = $3200. ($8000 is Saturday's total, not the difference.)"},
  {"id":"DI-W4-Q2","week":4,"category":"Data Interpretation","topic":"conversion","difficulty":"E","estSecs":45,"question":"An exchange rate is fixed at 1 AUD = 0.80 USD.\n\nMia converts 250 AUD into US dollars, spends 120 USD, then converts all the remaining US dollars back into AUD. How many AUD does she get back?","options":{"A":"96 AUD","B":"130 AUD","C":"80 AUD","D":"150 AUD","E":"100 AUD"},"answer":"E","explanation":"250 AUD x 0.80 = 200 USD. After spending 120 USD, 80 USD remain. Convert back: 80 / 0.80 = 100 AUD. (80 AUD forgets to convert the leftover USD; 130 comes from subtracting 120 directly from 250.)"},
  {"id":"DI-W4-Q3","week":4,"category":"Data Interpretation","topic":"mean comparison","difficulty":"M","estSecs":70,"question":"A company's monthly profit (in thousands of dollars) was:\nJan 12, Feb 15, Mar 11, Apr 18, May 22, Jun 18.\n\nFor how many of these months was the profit ABOVE the six-month mean?","options":{"A":"5","B":"2","C":"4","D":"1","E":"3"},"answer":"E","explanation":"Total = 12 + 15 + 11 + 18 + 22 + 18 = 96, so mean = 96 / 6 = 16 (i.e. $16,000). Months above 16: Apr 18, May 22, Jun 18 = 3 months. (Feb 15 is below the mean, a common miscount.)"},
  {"id":"DI-W4-Q4","week":4,"category":"Data Interpretation","topic":"conditional discount","difficulty":"H","estSecs":100,"question":"Stationery prices: Pen $2.50, Notebook $4.00, Highlighter $1.80.\nSpecial offer: buy 4 or more of ONE item and get 10% off that item's total.\n\nA student buys 5 pens, 3 notebooks and 4 highlighters. What is the total cost?","options":{"A":"$29.73","B":"$31.70","C":"$28.53","D":"$30.45","E":"$29.43"},"answer":"A","explanation":"Pens: 5 x $2.50 = $12.50; 5 is at least 4 so 10% off gives $11.25. Notebooks: 3 x $4.00 = $12.00; only 3, so NO discount. Highlighters: 4 x $1.80 = $7.20; 4 is at least 4 so 10% off gives $6.48. Total = 11.25 + 12.00 + 6.48 = $29.73. ($31.70 applies no discounts; $28.53 wrongly discounts the notebooks too; $30.45 discounts only the pens.)"},
  {"id":"DI-W4-Q5","week":4,"category":"Data Interpretation","topic":"shift hours","difficulty":"M","estSecs":70,"question":"A worker's shifts for the week:\nMon 8:30-15:00, Tue 9:00-17:30, Wed 8:00-12:30, Thu 10:00-18:00, Fri 8:30-14:00.\nShe is paid $22 per hour. What is her total pay for the week?","options":{"A":"$33","B":"$726","C":"$748","D":"$704","E":"$660"},"answer":"B","explanation":"Hours: Mon 6.5, Tue 8.5, Wed 4.5, Thu 8, Fri 5.5. Total = 6.5 + 8.5 + 4.5 + 8 + 5.5 = 33 hours. Pay = 33 x $22 = $726. ($33 is the number of hours, not the pay.)"},
  {"id":"DI-W4-Q6","week":4,"category":"Data Interpretation","topic":"percentage points","difficulty":"E","estSecs":45,"question":"400 people named their favourite season:\nSummer 140, Autumn 80, Winter 60, Spring 120.\n\nSummer's share was how many PERCENTAGE POINTS greater than Winter's share?","options":{"A":"15","B":"80","C":"25","D":"20","E":"35"},"answer":"D","explanation":"Summer = 140/400 = 35%. Winter = 60/400 = 15%. Difference = 35% - 15% = 20 percentage points. (80 is the difference in the raw number of people, 140 - 60, not in percentage points.)"},
  {"id":"DI-W4-Q7","week":4,"category":"Data Interpretation","topic":"best value / unit rate","difficulty":"M","estSecs":70,"question":"A shop sells the same juice in three sizes:\nSmall 250 mL for $2, Medium 400 mL for $3, Large 1 L (1000 mL) for $6.\n\nWhich size gives the MOST juice per dollar (the best value)?","options":{"A":"Small","B":"Medium","C":"Large","D":"Small and Medium are equal","E":"All three are equal value"},"answer":"C","explanation":"Juice per dollar: Small = 250 / 2 = 125 mL per $; Medium = 400 / 3 = about 133 mL per $; Large = 1000 / 6 = about 167 mL per $. The Large gives the most millilitres per dollar, so it is the best value. (Judging by lowest price alone would wrongly favour the Small.)"}
];
if (typeof module !== "undefined") { module.exports = { QUESTIONS, CATEGORIES }; }
